  const client = await createS3Client();
  return getSignedUrl(client, new GetObjectCommand({ Bucket: s3BucketName!, Key: key }), {
    expiresIn: presignedUrlExpiresInSeconds,
  });
}

function readMultipartFile(req: Request): Promise<{ buffer: Buffer; filename: string; mimeType: string; sizeBytes: number }> {
  return new Promise((resolve, reject) => {
    const body = req.body;
    const candidate = body && typeof body === 'object' && !Buffer.isBuffer(body)
      ? (body as { file?: unknown })
      : null;
    const file = candidate?.file;

    const parsed = multipartFileSchema.safeParse(file);
    if (!parsed.success) {
      reject(new Error('No uploaded file found in request body'));
      return;
    }

    if (parsed.data.size > uploadMaxBytes) {
      reject(new Error('File exceeds 1GB limit'));
      return;
    }

    resolve({
      buffer: parsed.data.buffer,
      filename: parsed.data.originalname,
      mimeType: parsed.data.mimetype,
      sizeBytes: parsed.data.size,
    });
  });
}

