type LinkSyncResponse = {
  success: boolean;
  document_id: string;
  linked_document_ids: string[];
};

async function assertVisibleDocument(id: string, workspaceId: string, userId: string, isAdmin: boolean) {
  const docResult = await pool.query(
    `SELECT id FROM documents
     WHERE id = $1 AND workspace_id = $2
       AND archived_at IS NULL
       AND deleted_at IS NULL
       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    [id, workspaceId, userId, isAdmin]
  );

  return (docResult.rowCount ?? 0) > 0;
}

async function validateTargetDocuments(
  targetIds: string[],
  workspaceId: string,
  userId: string,
  isAdmin: boolean
) {
  if (targetIds.length === 0) return true;

  const targetResult = await pool.query(
    `SELECT id FROM documents
     WHERE id = ANY($1::uuid[]) AND workspace_id = $2
       AND archived_at IS NULL
       AND deleted_at IS NULL
       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    [targetIds, workspaceId, userId, isAdmin]
  );

  return targetResult.rows.length === targetIds.length;
}

function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncSchema>) {
  return Array.from(
    new Set([
      ...(payload.target_ids ?? []),
      ...(payload.links ?? []),
      ...(payload.mentions ?? []),
      ...(payload.extracted_links ?? []),
      ...(payload.extracted_mentions ?? []),
    ])
  );
}

router.get('/:id/backlinks', authMiddleware, async (req: Request, res: Response) => {
  const parsedId = uuidParamSchema.safeParse(req.params.id);
  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });

  const userId = req.userId!;
  const workspaceId = req.workspaceId!;
  const { isAdmin } = await getVisibilityContext(userId, workspaceId);

  const visible = await assertVisibleDocument(parsedId.data, workspaceId, userId, isAdmin);
  if (!visible) return res.status(404).json({ error: 'Document not found' });

  const result = await pool.query(
    `SELECT DISTINCT ON (d.id)
        d.id,
        d.document_type,
        d.title
     FROM document_links dl
     JOIN documents d ON dl.source_id = d.id
     WHERE dl.target_id = $1 AND d.workspace_id = $2
       AND d.archived_at IS NULL
       AND d.deleted_at IS NULL
       AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
     ORDER BY d.id, dl.created_at DESC, d.created_at DESC`,
    [parsedId.data, workspaceId, userId, isAdmin]
  );

  return res.json(
    result.rows.map((row) => ({
      id: row.id,
      title: row.title,
      document_type: row.document_type,
    })) as BacklinkSummary[]
  );
});

router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
  const parsedId = uuidParamSchema.safeParse(req.params.id);
  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });

  const payload = req.body as unknown;
  const parsed = documentLinkSyncSchema.safeParse(payload);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });

  const userId = req.userId!;
  const workspaceId = req.workspaceId!;
  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
  const sourceId = parsedId.data;
  const extractedIds = buildSyncedLinkSet(parsed.data);

  const visible = await assertVisibleDocument(sourceId, workspaceId, userId, isAdmin);
  if (!visible) return res.status(404).json({ error: 'Document not found' });

  if (extractedIds.length === 0) {
    await pool.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
    return res.status(200).json({ success: true, document_id: sourceId, linked_document_ids: [] });
  }

  const uniqueExtractedIds = Array.from(new Set(extractedIds));
  if (!(await validateTargetDocuments(uniqueExtractedIds, workspaceId, userId, isAdmin))) {
    return res.status(400).json({ error: 'One or more target documents not found' });
  }

  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);

    const values = uniqueExtractedIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
    const params = uniqueExtractedIds.flatMap((targetId) => [sourceId, targetId]);
    await client.query(
      `INSERT INTO document_links (source_id, target_id)
       VALUES ${values}
       ON CONFLICT (source_id, target_id) DO NOTHING`,
      params
    );

    const responseRows = await client.query(
      `SELECT DISTINCT target_id
       FROM document_links
       WHERE source_id = $1
       ORDER BY target_id ASC`,
      [sourceId]
    );

    await client.query('COMMIT');
    return res.status(200).json({
      success: true,
      document_id: sourceId,
      linked_document_ids: responseRows.rows.map((row) => row.target_id),
    } satisfies LinkSyncResponse);
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
});

