/**
 * Global upload tracker for navigation warnings.
 */

export interface UploadInfo {
  id: string;
  filename: string;
  progress: number;
  active: boolean;
}

export interface UploadTrackerSnapshot {
  uploadCount: number;
  activeUploads: UploadInfo[];
}

export interface UploadNavigationWarningState extends UploadTrackerSnapshot {
  isBlocked: boolean;
  proceed: () => void;
  stay: () => void;
}

export interface UploadNavigationWarningViewState extends UploadNavigationWarningState {
  isOpen: boolean;
}

export interface UploadNavigationWarningHookState extends UploadNavigationWarningViewState {
  message: string;
}

const activeUploads = new Map<string, UploadInfo>();
const listeners = new Set<() => void>();
let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;

function hasWindow(): boolean {
  return typeof window !== 'undefined';
}

function cloneUpload(upload: UploadInfo): UploadInfo {
  return { ...upload };
}

function notifyListeners(): void {
  listeners.forEach((listener) => listener());
}

function getUploadMessage(uploadCount: number): string {
  return uploadCount === 1
    ? '1 upload is still in progress.'
    : `${uploadCount} uploads are still in progress.`;
}

function syncBeforeUnloadListener(): void {
  if (!hasWindow()) return;

  if (beforeUnloadListener) {
    window.removeEventListener('beforeunload', beforeUnloadListener);
    beforeUnloadListener = null;
  }

  if (!hasActiveUploads()) return;

  beforeUnloadListener = (event: BeforeUnloadEvent) => {
    if (!hasActiveUploads()) return;
    event.preventDefault();
    event.returnValue = getUploadMessage(getUploadCount());
    return event.returnValue;
  };

  window.addEventListener('beforeunload', beforeUnloadListener);
}

export function registerUpload(id: string, filename: string): void {
  activeUploads.set(id, { id, filename, progress: 0, active: true });
  syncBeforeUnloadListener();
  notifyListeners();
}

export function updateUploadProgress(id: string, progress: number): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.progress = progress;
  upload.active = true;
  syncBeforeUnloadListener();
  notifyListeners();
}

export function markUploadInactive(id: string): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.active = false;
  syncBeforeUnloadListener();
  notifyListeners();
}

export function unregisterUpload(id: string): void {
  activeUploads.delete(id);
  syncBeforeUnloadListener();
  notifyListeners();
}

export function clearUploads(): void {
  activeUploads.clear();
  syncBeforeUnloadListener();
  notifyListeners();
}

export function getUploadCount(): number {
  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
}

export function getActiveUploads(): UploadInfo[] {
  return Array.from(activeUploads.values())
    .filter((upload) => upload.active)
    .map(cloneUpload);
}

export function hasActiveUploads(): boolean {
  return getUploadCount() > 0;
}

export function getUploadSnapshot(): UploadTrackerSnapshot {
  return {
    uploadCount: getUploadCount(),
    activeUploads: getActiveUploads(),
  };
}

export function subscribeToUploads(listener: () => void): () => void {
  listeners.add(listener);
  listener();
  return () => listeners.delete(listener);
}

export function getUploadNavigationWarningState(): UploadNavigationWarningState {
  const snapshot = getUploadSnapshot();
  return {
    ...snapshot,
    isBlocked: snapshot.uploadCount > 0,
    proceed: clearUploads,
    stay: () => undefined,
  };
}

export function getUploadNavigationWarningViewState(): UploadNavigationWarningViewState {
  const state = getUploadNavigationWarningState();
  return {
    ...state,
    isOpen: state.isBlocked,
  };
}

export function getUploadNavigationWarningMessage(uploadCount: number): string {
  return getUploadMessage(uploadCount);
}

export function getUploadNavigationWarningHookState(): UploadNavigationWarningHookState {
  const state = getUploadNavigationWarningViewState();
  return {
    ...state,
    message: getUploadNavigationWarningMessage(state.uploadCount),
  };
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';

export type CommentStatus = 'open' | 'resolved' | 'deleted';

export interface CommentUser {
  id: string;
  name?: string | null;
  email?: string | null;
  avatarUrl?: string | null;
}

export interface CommentThread {
  id: string;
  postId: string;
  parentId: string | null;
  content: string;
  status: CommentStatus;
  createdAt: string;
  updatedAt: string;
  resolvedAt?: string | null;
  resolvedById?: string | null;
  author?: CommentUser | null;
  replies?: CommentThread[];
}

export interface CommentsThreadListResponse {
  threads: CommentThread[];
}

export interface CreateCommentInput {
  postId: string;
  content: string;
  parentId?: string | null;
}

export interface UpdateCommentInput {
  content: string;
}

export interface ResolveCommentInput {
  resolved: boolean;
}

const COMMENTS_QUERY_KEY = ['comments'] as const;

async function apiRequest<T>(path: string, init?: RequestInit): Promise<T> {
  const response = await fetch(path, {
    headers: {
      'Content-Type': 'application/json',
      ...(init?.headers ?? {}),
    },
    ...init,
  });

  if (!response.ok) {
    let message = `Request failed with status ${response.status}`;
    try {
      const body = (await response.json()) as { message?: string; error?: string };
      message = body.message || body.error || message;
    } catch {
      // ignore parse failures
    }
    const error = new Error(message) as Error & { status?: number };
    error.status = response.status;
    throw error;
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return (await response.json()) as T;
}

async function fetchCommentThreads(postId: string): Promise<CommentThread[]> {
  const { threads } = await apiRequest<CommentsThreadListResponse>(`/api/posts/${postId}/comments`);
  return threads;
}

async function createComment(input: CreateCommentInput): Promise<CommentThread> {
  return apiRequest<CommentThread>(`/api/posts/${input.postId}/comments`, {
    method: 'POST',
    body: JSON.stringify({
      content: input.content,
      parentId: input.parentId ?? null,
    }),
  });
}

async function replyToComment(commentId: string, content: string): Promise<CommentThread> {
  return apiRequest<CommentThread>(`/api/comments/${commentId}/replies`, {
    method: 'POST',
    body: JSON.stringify({ content }),
  });
}

async function updateComment(commentId: string, content: string): Promise<CommentThread> {
  return apiRequest<CommentThread>(`/api/comments/${commentId}`, {
    method: 'PATCH',
    body: JSON.stringify({ content }),
  });
}

async function resolveComment(commentId: string, resolved: boolean): Promise<CommentThread> {
  return apiRequest<CommentThread>(`/api/comments/${commentId}/resolve`, {
    method: 'PATCH',
    body: JSON.stringify({ resolved }),
  });
}

async function deleteComment(commentId: string): Promise<void> {
  await apiRequest<void>(`/api/comments/${commentId}`, {
    method: 'DELETE',
  });
}

export function useCommentsQuery(postId?: string) {
  const queryClient = useQueryClient();

  const commentsQuery = useQuery({
    queryKey: [...COMMENTS_QUERY_KEY, postId] as const,
    queryFn: () => {
      if (!postId) throw new Error('postId is required');
      return fetchCommentThreads(postId);
    },
    enabled: Boolean(postId),
  });

  const invalidateComments = async () => {
    if (!postId) return;
    await queryClient.invalidateQueries({ queryKey: [...COMMENTS_QUERY_KEY, postId] });
  };

  const createMutation = useMutation({
    mutationFn: createComment,
    meta: { operation: 'create-comment' },
    onSuccess: invalidateComments,
  });

  const replyMutation = useMutation({
    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => replyToComment(commentId, content),
    meta: { operation: 'reply-comment' },
    onSuccess: invalidateComments,
  });

  const updateMutation = useMutation({
    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => updateComment(commentId, content),
    meta: { operation: 'update-comment' },
    onSuccess: invalidateComments,
  });

  const resolveMutation = useMutation({
    mutationFn: ({ commentId, resolved }: { commentId: string; resolved: boolean }) => resolveComment(commentId, resolved),
    meta: { operation: 'resolve-comment' },
    onSuccess: invalidateComments,
  });

  const deleteMutation = useMutation({
    mutationFn: deleteComment,
    meta: { operation: 'delete-comment' },
    onSuccess: invalidateComments,
  });

  return {
    ...commentsQuery,
    comments: commentsQuery.data ?? [],
    createComment: createMutation.mutateAsync,
    replyToComment: replyMutation.mutateAsync,
    updateComment: updateMutation.mutateAsync,
    resolveComment: resolveMutation.mutateAsync,
    deleteComment: deleteMutation.mutateAsync,
    isCreatingComment: createMutation.isPending,
    isReplyingToComment: replyMutation.isPending,
    isUpdatingComment: updateMutation.isPending,
    isResolvingComment: resolveMutation.isPending,
    isDeletingComment: deleteMutation.isPending,
  };
}

