{"success":true,"content":"     1	import { Router, type Request, type Response } from 'express';
     2	import { z } from 'zod';
     3	import { pool } from '../db/client.js';
     4	import { authMiddleware } from '../middleware/auth.js';
     5	import { getVisibilityContext, VISIBILITY_FILTER_SQL } from '../middleware/visibility.js';
     6	
     7	const router = Router();
     8	
     9	const uuidParamSchema = z.string().uuid();
    10	const documentLinkSyncSchema = z.object({
    11	  target_ids: z.array(z.string().uuid()).default([]),
    12	  links: z.array(z.string().uuid()).default([]),
    13	  mentions: z.array(z.string().uuid()).default([]),
    14	  extracted_links: z.array(z.string().uuid()).default([]),
    15	  extracted_mentions: z.array(z.string().uuid()).default([]),
    16	});
    17	
    18	type BacklinkSummary = {
    19	  id: string;
    20	  title: string;
    21	  document_type: string;
    22	};
    23	
    24	type LinkSyncResponse = {
    25	  success: boolean;
    26	  document_id: string;
    27	  linked_document_ids: string[];
    28	};
    29	
    30	async function assertVisibleDocument(id: string, workspaceId: string, userId: string, isAdmin: boolean) {
    31	  const docResult = await pool.query(
    32	    `SELECT id FROM documents
    33	     WHERE id = $1 AND workspace_id = $2
    34	       AND archived_at IS NULL
    35	       AND deleted_at IS NULL
    36	       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    37	    [id, workspaceId, userId, isAdmin]
    38	  );
    39	
    40	  return (docResult.rowCount ?? 0) > 0;
    41	}
    42	
    43	async function validateTargetDocuments(
    44	  targetIds: string[],
    45	  workspaceId: string,
    46	  userId: string,
    47	  isAdmin: boolean
    48	) {
    49	  if (targetIds.length === 0) return true;
    50	
    51	  const targetResult = await pool.query(
    52	    `SELECT id FROM documents
    53	     WHERE id = ANY($1::uuid[]) AND workspace_id = $2
    54	       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    55	    [targetIds, workspaceId, userId, isAdmin]
    56	  );
    57	
    58	  return targetResult.rows.length === targetIds.length;
    59	}
    60	
    61	function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncSchema>) {
    62	  return Array.from(
    63	    new Set([
    64	      ...(payload.target_ids ?? []),
    65	      ...(payload.links ?? []),
    66	      ...(payload.mentions ?? []),
    67	      ...(payload.extracted_links ?? []),
    68	      ...(payload.extracted_mentions ?? []),
    69	    ])
    70	  );
    71	}
    72	
    73	router.get('/:id', authMiddleware, async (req: Request, res: Response) => {
    74	  const parsedId = uuidParamSchema.safeParse(req.params.id);
    75	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
    76	
    77	  const userId = req.userId!;
    78	  const workspaceId = req.workspaceId!;
    79	  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
    80	
    81	  const visible = await assertVisibleDocument(parsedId.data, workspaceId, userId, isAdmin);
    82	  if (!visible) return res.status(404).json({ error: 'Document not found' });
    83	
    84	  const result = await pool.query(
    85	    `SELECT DISTINCT ON (d.id)
    86	        d.id,
    87	        d.document_type,
    88	        d.title
    89	     FROM document_links dl
    90	     JOIN documents d ON dl.source_id = d.id
    91	     WHERE dl.target_id = $1 AND d.workspace_id = $2
    92	       AND d.archived_at IS NULL
    93	       AND d.deleted_at IS NULL
    94	       AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
    95	     ORDER BY d.id, dl.created_at DESC, d.created_at DESC`,
    96	    [parsedId.data, workspaceId, userId, isAdmin]
    97	  );
    98	
    99	  return res.json(
   100	    result.rows.map((row) => ({
   101	      id: row.id,
   102	      title: row.title,
   103	      document_type: row.document_type,
   104	    })) satisfies BacklinkSummary[]
   105	  );
   106	});
   107	
   108	router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
   109	  const parsedId = uuidParamSchema.safeParse(req.params.id);
   110	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
   111	
   112	  const payload = req.body as unknown;
   113	  const parsed = documentLinkSyncSchema.safeParse(payload);
   114	  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
   115	
   116	  const userId = req.userId!;
   117	  const workspaceId = req.workspaceId!;
   118	  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
   119	  const sourceId = parsedId.data;
   120	  const extractedIds = buildSyncedLinkSet(parsed.data);
   121	
   122	  const visible = await assertVisibleDocument(sourceId, workspaceId, userId, isAdmin);
   123	  if (!visible) return res.status(404).json({ error: 'Document not found' });
   124	
   125	  if (extractedIds.length === 0) {
   126	    await pool.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   127	    return res.status(200).json({ success: true, document_id: sourceId, linked_document_ids: [] } satisfies LinkSyncResponse);
   128	  }
   129	
   130	  const uniqueExtractedIds = Array.from(new Set(extractedIds));
   131	  if (!(await validateTargetDocuments(uniqueExtractedIds, workspaceId, userId, isAdmin))) {
   132	    return res.status(400).json({ error: 'One or more target documents not found' });
   133	  }
   134	
   135	  const client = await pool.connect();
   136	  try {
   137	    await client.query('BEGIN');
   138	    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   139	
   140	    const values = uniqueExtractedIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
   141	    const params = uniqueExtractedIds.flatMap((targetId) => [sourceId, targetId]);
   142	    await client.query(
   143	      `INSERT INTO document_links (source_id, target_id)
   144	       VALUES ${values}
   145	       ON CONFLICT (source_id, target_id) DO NOTHING`,
   146	      params
   147	    );
   148	
   149	    const responseRows = await client.query(
   150	      `SELECT DISTINCT target_id
   151	       FROM document_links
   152	       WHERE source_id = $1
   153	       ORDER BY target_id ASC`,
   154	      [sourceId]
   155	    );
   156	
   157	    await client.query('COMMIT');
   158	    return res.status(200).json({
   159	      success: true,
   160	      document_id: sourceId,
   161	      linked_document_ids: responseRows.rows.map((row) => row.target_id),
   162	    } satisfies LinkSyncResponse);
   163	  } catch (err) {
   164	    await client.query('ROLLBACK');
   165	    throw err;
   166	  } finally {
   167	    client.release();
   168	  }
   169	});
   170	
   171	export default router;
   172	","total_lines":172}

