export async function uploadFile(
  file: File,
  onProgress?: ProgressCallback,
  signal?: AbortSignal,
): Promise<UploadResult> {
  if (signal?.aborted) throw getAbortError();

  const progressTracker = createUploadProgressTracker(onProgress);
  const updateProgress = (updates: Partial<UploadProgress>) =>
    progressTracker.update(updates);

  try {
    updateProgress({ status: "pending", progress: 5 });
    const request = await requestUpload(file, signal);
    updateProgress({ fileId: request.fileId, progress: 20 });

    const uploadUrl = buildUploadUrl(request);
    const method = getUploadMethod(request);
    const mimeType = getUploadMimeType(file);
    const isLocalUpload = isLocalUploadMethod(request);

    updateProgress({ status: "uploading", progress: 40 });
    if (isLocalUpload) {
      const formData = new FormData();
      formData.append("file", file);
      const headers: Record<string, string> = {};
      if (method === "POST")
        headers["X-CSRF-Token"] = await getCachedCsrfToken();
      const uploadRes = await uploadViaFetch(uploadUrl, {
        method,
        headers: Object.keys(headers).length > 0 ? headers : undefined,
        credentials: "include",
        body: formData,
        signal,
      });

      if (!uploadRes.ok) {
        throw new Error(
          await getUploadErrorMessage(uploadRes, "Failed to upload file"),
        );
      }
    } else {
      const uploadRes = await uploadViaFetch(uploadUrl, {
        method: "PUT",
        headers: { "Content-Type": mimeType },
        body: file,
        signal,
      });

      if (!uploadRes.ok) {
        throw new Error(
          await getUploadErrorMessage(uploadRes, "Failed to upload file"),
        );
      }
    }

    updateProgress({ status: "confirming", progress: 85 });
    const result = isLocalUpload
      ? await finalizeLocalUpload(request, signal)
      : await finalizeRemoteUpload(request, file, signal);
    updateProgress({ status: "complete", progress: 100 });
    return result;
  } catch (error) {
    if (signal?.aborted) {
      updateProgress({ status: "error", error: "Upload cancelled" });
      throw getAbortError();
    }
    updateProgress({
      status: "error",
      error: parseErrorMessage(error, "Upload failed"),
    });
    throw error;
  }
}

