import { useSyncExternalStore } from "react";

import {
  getUploadNavigationWarningHookState,
  subscribeToUploads,
} from "../services/uploadTracker.js";

export function useUploadNavigationWarning() {
  return useSyncExternalStore(
    subscribeToUploads,
    getUploadNavigationWarningHookState,
    getUploadNavigationWarningHookState,
  );
}

export function UploadNavigationWarning() {
  const state = useUploadNavigationWarning();

  if (!state.isOpen) return null;

  return (
    <div role="alert" aria-live="assertive">
      <p>{state.message}</p>
    </div>
  );
}

