import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { apiDelete, apiGet, apiPatch, apiPost } from '@/lib/api';

export interface Comment {
  id: string;
  document_id: string;
  comment_id: string;
  parent_id: string | null;
  author_id: string;
  content: string;
  resolved_at: string | null;
  resolved_by: string | null;
  deleted_at: string | null;
  created_at: string;
  updated_at: string;
}

export interface CommentThread {
  comment_id: string;
  root: Comment | null;
  replies: Comment[];
}

export interface CommentThreadListResponse {
  comments: CommentThread[];
}

export interface CreateCommentInput {
  content: string;
  parent_id?: string | null;
  comment_id?: string | null;
}

export interface CreateCommentVariables extends CreateCommentInput {
  documentId: string;
}

export interface UpdateCommentInput {
  id: string;
  content: string;
}

export interface ResolveCommentInput {
  id: string;
}

export interface DeleteCommentInput {
  id: string;
}

export const commentKeys = {
  all: ['comments'] as const,
  document: (documentId: string) => [...commentKeys.all, 'document', documentId] as const,
};

function extractError(message: string, response: Response): Error & { status: number } {
  const error = new Error(message) as Error & { status: number };
  error.status = response.status;
  return error;
}

async function fetchComments(documentId: string): Promise<CommentThread[]> {
  const res = await apiGet(`/api/documents/${documentId}/comments`);
  if (!res.ok) {
    throw extractError('Failed to fetch comments', res);
  }

  const data = (await res.json()) as CommentThreadListResponse;
  return data.comments ?? [];
}

async function createCommentApi(documentId: string, input: CreateCommentInput): Promise<Comment> {
  const payload: Record<string, unknown> = { content: input.content };
  if (input.parent_id !== undefined) payload.parent_id = input.parent_id;
  if (input.comment_id !== undefined) payload.comment_id = input.comment_id;

  const res = await apiPost(`/api/documents/${documentId}/comments`, payload);
  if (!res.ok) {
    throw extractError('Failed to create comment', res);
  }

  return (await res.json()) as Comment;
}

async function updateCommentApi(input: UpdateCommentInput): Promise<Comment> {
  const res = await apiPatch(`/api/comments/${input.id}`, {
    content: input.content,
  });

  if (!res.ok) {
    throw extractError('Failed to update comment', res);
  }

  return (await res.json()) as Comment;
}

async function resolveCommentApi(input: ResolveCommentInput): Promise<Comment> {
  const res = await apiPost(`/api/comments/${input.id}/resolve`, {});

  if (!res.ok) {
    throw extractError('Failed to resolve comment', res);
  }

  return (await res.json()) as Comment;
}

async function deleteCommentApi(input: DeleteCommentInput): Promise<void> {
  const res = await apiDelete(`/api/comments/${input.id}`);
  if (!res.ok) {
    throw extractError('Failed to delete comment', res);
  }
}

function normalizeThread(value: CommentThread | Comment): CommentThread {
  if ('replies' in value) return value;
  return {
    comment_id: value.comment_id,
    root: value.parent_id === null ? value : null,
    replies: value.parent_id === null ? [] : [value],
  };
}

function mergeThreadList(old: CommentThread[] | undefined, incoming: CommentThread): CommentThread[] {
  const existing = old ?? [];
  const next = existing.filter((thread) => thread.comment_id !== incoming.comment_id);
  return [...next, incoming];
}

function upsertComment(old: CommentThread[] | undefined, comment: Comment): CommentThread[] {
  return mergeThreadList(old, normalizeThread(comment));
}

function removeCommentFromThreads(old: CommentThread[] | undefined, commentId: string): CommentThread[] {
  const existing = old ?? [];
  return existing
    .map((thread) => {
      if (thread.root?.id === commentId) {
        return thread.replies.length > 0 ? { ...thread, root: null } : null;
      }
      if (thread.replies.some((reply) => reply.id === commentId)) {
        const replies = thread.replies.filter((reply) => reply.id !== commentId);
        return thread.root || replies.length > 0 ? { ...thread, replies } : null;
      }
      return thread;
    })
    .filter((thread): thread is CommentThread => thread !== null);
}

export function getCommentThreadResolvedAt(thread: CommentThread): string | null {
  return thread.root?.resolved_at ?? thread.replies.find((reply) => reply.resolved_at !== null)?.resolved_at ?? null;
}

export function useCommentsQuery(documentId: string) {
  return useQuery({
    queryKey: commentKeys.document(documentId),
    queryFn: () => fetchComments(documentId),
    enabled: !!documentId,
    staleTime: 1000 * 60 * 2,
    refetchOnMount: 'always',
  });
}

export function useCreateComment() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ documentId, ...input }: CreateCommentVariables) => createCommentApi(documentId, input),
    onSuccess: (comment, variables) => {
      queryClient.setQueryData<CommentThread[]>(commentKeys.document(variables.documentId), (old) => mergeThreadList(old, normalizeThread(comment)));
      queryClient.invalidateQueries({ queryKey: commentKeys.document(variables.documentId) });
    },
  });
}

export function useReplyComment() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ documentId, threadCommentId, content }: { documentId: string; threadCommentId: string; content: string }) =>
      createCommentApi(documentId, { content, comment_id: threadCommentId, parent_id: threadCommentId }),
    onSuccess: (comment, variables) => {
      queryClient.setQueryData<CommentThread[]>(commentKeys.document(variables.documentId), (old) => upsertComment(old, comment));
      queryClient.invalidateQueries({ queryKey: commentKeys.document(variables.documentId) });
    },
  });
}

export function useUpdateComment() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: updateCommentApi,
    onSuccess: (comment) => {
      queryClient.setQueryData<CommentThread[]>(commentKeys.document(comment.document_id), (old) => upsertComment(old, comment));
      queryClient.invalidateQueries({ queryKey: commentKeys.document(comment.document_id) });
    },
  });
}

export function useResolveComment() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: resolveCommentApi,
    onSuccess: (comment) => {
      queryClient.setQueryData<CommentThread[]>(commentKeys.document(comment.document_id), (old) => upsertComment(old, comment));
      queryClient.invalidateQueries({ queryKey: commentKeys.document(comment.document_id) });
    },
  });
}

export function useDeleteComment() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: deleteCommentApi,
    onSuccess: (_data, variables) => {
      queryClient.setQueriesData<CommentThread[]>({ queryKey: commentKeys.all }, (old) => removeCommentFromThreads(old, variables.id));
      queryClient.invalidateQueries({ queryKey: commentKeys.all });
    },
  });
}

