    window.dispatchEvent(event);
    return {
      defaultPrevented: event.defaultPrevented,
      returnValue: event.returnValue,
    };
  });

  expect(beforeUnloadResult.defaultPrevented).toBeTruthy();
  expect(beforeUnloadResult.returnValue).toBeTruthy();
});

