import { randomUUID } from 'crypto';
import { Router, type Request, type Response } from 'express';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const commentsRouter = Router();

function parseUuid(value: unknown): string | null {
  return typeof value === 'string' && UUID_REGEX.test(value) ? value : null;
}

function requireUserId(req: Request): string {
  if (!req.userId) throw new Error('Missing authenticated user');
  return req.userId;
}

function requireWorkspaceId(req: Request): string {
  if (!req.workspaceId) throw new Error('Missing workspace context');
  return req.workspaceId;
}

type CommentRow = {
  id: string;
  document_id: string;
  comment_id: string;
  parent_id: string | null;
  author_id: string;
  content: string;
  resolved_at: string | null;
  resolved_by: string | null;
  deleted_at: string | null;
  created_at: string;
  updated_at: string;
};

type CommentWithWorkspaceRow = CommentRow & { workspace_id: string };

type CommentThreadResponse = {
  comment_id: string;
  root: ReturnType<typeof mapCommentRow> | null;
  replies: ReturnType<typeof mapCommentRow>[];
};

function mapCommentRow(row: CommentRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    comment_id: row.comment_id,
    parent_id: row.parent_id,
    author_id: row.author_id,
    content: row.content,
    resolved_at: row.resolved_at,
    resolved_by: row.resolved_by,
    deleted_at: row.deleted_at,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

function threadSortValue(thread: CommentThreadResponse): string {
  return thread.root?.created_at ?? thread.replies[0]?.created_at ?? '';
}

async function getCommentWithWorkspace(id: string) {
  return pool.query<CommentWithWorkspaceRow>(
    'SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1',
    [id]
  );
}

async function isWorkspaceAdmin(workspaceId: string, userId: string): Promise<boolean> {
  const result = await pool.query('SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2', [workspaceId, userId]);
  return result.rows[0]?.role === 'admin' || result.rows[0]?.role === 'owner';
}

commentsRouter.get('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseUuid(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const workspaceId = requireWorkspaceId(req);
  const document = await pool.query('SELECT id, workspace_id FROM documents WHERE id = $1 AND workspace_id = $2', [documentId, workspaceId]);
  if (document.rowCount === 0) return res.status(404).json({ error: 'Document not found' });

  const rows = await pool.query<CommentRow>(
    'SELECT id, document_id, comment_id, parent_id, author_id, content, resolved_at, resolved_by, deleted_at, created_at, updated_at FROM comments WHERE document_id = $1 AND deleted_at IS NULL ORDER BY comment_id ASC, parent_id NULLS FIRST, created_at ASC',
    [documentId]
  );

  const threads = new Map<string, CommentThreadResponse>();
  for (const row of rows.rows) {
    const comment = mapCommentRow(row);
    const thread = threads.get(comment.comment_id) ?? { comment_id: comment.comment_id, root: null, replies: [] };
    if (comment.parent_id === null) thread.root = comment;
    else thread.replies.push(comment);
    threads.set(comment.comment_id, thread);
  }

  const comments = Array.from(threads.values()).sort((a, b) => threadSortValue(a).localeCompare(threadSortValue(b)));
  return res.json({ comments });
});

