   113	
   114	  const payload = req.body as unknown;
   115	  const parsed = documentLinkSyncSchema.safeParse(payload);
   116	  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
   117	
   118	  const userId = req.userId!;
   119	  const workspaceId = req.workspaceId!;
   120	  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
   121	  const sourceId = parsedId.data;
   122	  const extractedIds = buildSyncedLinkSet(parsed.data);
   123	
   124	  const visible = await assertVisibleDocument(sourceId, workspaceId, userId, isAdmin);
   125	  if (!visible) return res.status(404).json({ error: 'Document not found' });
   126	
