   136	
   137	  const client = await pool.connect();
   138	  try {
   139	    await client.query('BEGIN');
   140	    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   141	
   142	    const values = uniqueExtractedIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
   143	    const params = uniqueExtractedIds.flatMap((targetId) => [sourceId, targetId]);
   144	    await client.query(
   145	      `INSERT INTO document_links (source_id, target_id)
   146	       VALUES ${values}
   147	       ON CONFLICT (source_id, target_id) DO NOTHING`,
   148	      params
   149	    );
   150	
   151	    const responseRows = await client.query(
   152	      `SELECT DISTINCT target_id
   153	       FROM document_links
   154	       WHERE source_id = $1
   155	       ORDER BY target_id ASC`,
   156	      [sourceId]
   157	    );
   158	
   159	    await client.query('COMMIT');
   160	    return res.status(200).json({
   161	      success: true,
   162	      document_id: sourceId,
   163	      linked_document_ids: responseRows.rows.map((row) => row.target_id),
   164	    } satisfies LinkSyncResponse);
   165	  } catch (err) {
   166	    await client.query('ROLLBACK');
   167	    throw err;
   168	  } finally {
   169	    client.release();
