function mergeThreadList(old: CommentThread[] | undefined, incoming: CommentThread): CommentThread[] {
  const existing = old ?? [];
  const next = existing.filter((thread) => thread.comment_id !== incoming.comment_id);
  return [...next, incoming].sort((a, b) => {
    const aTime = a.root?.created_at ?? a.replies[0]?.created_at ?? '';
    const bTime = b.root?.created_at ?? b.replies[0]?.created_at ?? '';
    return aTime.localeCompare(bTime);
  });
}

