import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import request from 'supertest';
import crypto from 'crypto';
import { createApp } from '../app.js';
import { pool } from '../db/client.js';

describe('Files API', () => {
  const app = createApp('http://localhost:5173');
  const testRunId = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
  const testEmail = `files-${testRunId}@ship.local`;
  const testWorkspaceName = `Files Test ${testRunId}`;

  let sessionCookie: string;
  let csrfToken: string;
  let testWorkspaceId: string;
  let testUserId: string;

  function usesS3Storage() {
    return process.env.FILES_STORAGE_PROVIDER === 's3' || process.env.UPLOADS_PROVIDER === 's3' || !!process.env.S3_UPLOADS_BUCKET;
  }

  beforeAll(async () => {
    const workspaceResult = await pool.query(
      `INSERT INTO workspaces (name) VALUES ($1)
       RETURNING id`,
      [testWorkspaceName]
    );
    testWorkspaceId = workspaceResult.rows[0].id;

    const userResult = await pool.query(
      `INSERT INTO users (email, password_hash, name)
       VALUES ($1, 'test-hash', 'Files Test User')
       RETURNING id`,
      [testEmail]
    );
    testUserId = userResult.rows[0].id;

    await pool.query(
      `INSERT INTO workspace_memberships (workspace_id, user_id, role)
       VALUES ($1, $2, 'member')`,
      [testWorkspaceId, testUserId]
    );

    const sessionId = crypto.randomBytes(32).toString('hex');
    await pool.query(
      `INSERT INTO sessions (id, user_id, workspace_id, expires_at)
       VALUES ($1, $2, $3, now() + interval '1 hour')`,
      [sessionId, testUserId, testWorkspaceId]
    );
    sessionCookie = `session_id=${sessionId}`;

    const csrfRes = await request(app).get('/api/csrf-token').set('Cookie', sessionCookie);
    csrfToken = csrfRes.body.token;
    const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || '';
    if (connectSidCookie) {
      sessionCookie = `${sessionCookie}; ${connectSidCookie}`;
    }
  });

  afterAll(async () => {
    await pool.query('DELETE FROM files WHERE workspace_id = $1', [testWorkspaceId]);
    await pool.query('DELETE FROM sessions WHERE user_id = $1', [testUserId]);
    await pool.query('DELETE FROM workspace_memberships WHERE user_id = $1', [testUserId]);
    await pool.query('DELETE FROM users WHERE id = $1', [testUserId]);
    await pool.query('DELETE FROM workspaces WHERE id = $1', [testWorkspaceId]);
  });

  it('validates upload-request payloads and supports local upload success plus metadata/download URLs', async () => {
    expect(usesS3Storage()).toBe(false);

    const invalidIdRes = await request(app)
      .get('/api/files/not-a-uuid')
      .set('Cookie', sessionCookie);

    expect(invalidIdRes.status).toBe(400);
    expect(invalidIdRes.body.error).toBe('Invalid file ID format');

    const missingFilenameRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        mimeType: 'image/png',
        sizeBytes: 1024,
      });
    expect(missingFilenameRes.status).toBe(400);

    const blockedRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'dangerous.exe',
        mimeType: 'application/octet-stream',
        sizeBytes: 1024,
      });

    expect(blockedRes.status).toBe(400);
    expect(blockedRes.body.error).toBe('File type not allowed');

    const requestRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'test.png',
        mimeType: 'image/png',
        sizeBytes: 1024,
      });

    expect(requestRes.status).toBe(201);
    expect(requestRes.body.id).toMatch(/^[0-9a-f-]{36}$/i);
    expect(requestRes.body).toMatchObject({
      id: requestRes.body.id,
      filename: 'test.png',
      mimeType: 'image/png',
      sizeBytes: 1024,
      status: 'pending',
      downloadUrl: null,
      uploadUrl: null,
      method: 'POST',
      expiresInSeconds: null,
      storageKey: `${requestRes.body.id}.png`,
      uploadEndpoint: expect.stringContaining(`/api/files/upload/${requestRes.body.id}`),
    });

    const uploadRes = await request(app)
      .post(requestRes.body.uploadEndpoint)
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .attach('file', Buffer.from('fake-image-content'), 'test.png');

    expect(uploadRes.status).toBe(200);
    expect(uploadRes.body).toMatchObject({
      id: requestRes.body.id,
      filename: 'test.png',
      mimeType: 'image/png',
      sizeBytes: 1024,
      status: 'uploaded',
      downloadUrl: `/uploads/${requestRes.body.id}.png`,
    });

    const fileRes = await request(app)
      .get(`/api/files/${requestRes.body.id}`)
      .set('Cookie', sessionCookie);

    expect(fileRes.status).toBe(200);
    expect(fileRes.body).toMatchObject({
      id: requestRes.body.id,
      filename: 'test.png',
      mimeType: 'image/png',
      sizeBytes: 1024,
      status: 'uploaded',
      downloadUrl: `/uploads/${requestRes.body.id}.png`,
    });
    expect(fileRes.body.createdAt).toBeTruthy();
    expect(fileRes.body.uploadedAt).toBeTruthy();
    expect(fileRes.body.failedAt).toBeNull();
    expect(fileRes.body.errorMessage).toBeNull();
  }, 15000);

  it('validates file IDs and rejects dangerous extensions', async () => {
    const invalidIdRes = await request(app)
      .get('/api/files/not-a-uuid')
      .set('Cookie', sessionCookie);

    expect(invalidIdRes.status).toBe(400);
    expect(invalidIdRes.body.error).toBe('Invalid file ID format');

    const dangerousRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'malware.exe',
        mimeType: 'application/octet-stream',
        sizeBytes: 1024,
      });

    expect(dangerousRes.status).toBe(400);
    expect(dangerousRes.body.error).toBe('File type not allowed');
  });

  it('returns a presigned upload contract when S3 is enabled', async () => {
    if (!usesS3Storage()) {
      return;
    }

    const requestRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'presigned-test.png',
        mimeType: 'image/png',
        sizeBytes: 1024,
      });

    expect(requestRes.status).toBe(201);
    expect(requestRes.body).toMatchObject({
      uploadType: 's3',
      uploadUrl: expect.stringMatching(/^https?:\/\//),
      method: 'PUT',
      expiresInSeconds: 900,
      file: {
        filename: 'presigned-test.png',
        downloadUrl: null,
      },
    });
    expect(requestRes.body.uploadUrl).toContain('X-Amz-Signature');
  });

  it('GET /api/files/:id returns file metadata', async () => {
    const uploadRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'metadata-test.png',
        mimeType: 'image/png',
        sizeBytes: 3072,
      });

    const fileId = uploadRes.body.id;

    if (!usesS3Storage()) {
      await request(app)
        .post(`/api/files/upload/${fileId}`)
        .set('Cookie', sessionCookie)
        .set('x-csrf-token', csrfToken)
        .attach('file', Buffer.from('fake-image-content'), 'metadata-test.png');
    }

    const res = await request(app)
      .get(`/api/files/${fileId}`)
      .set('Cookie', sessionCookie);

    expect(res.status).toBe(200);
    expect(res.body).toHaveProperty('id');
    expect(res.body).toHaveProperty('filename');
    expect(res.body).toHaveProperty('mimeType');
    expect(res.body).toHaveProperty('sizeBytes');
    expect(res.body).toHaveProperty('status');
    expect(res.body.filename).toBe('metadata-test.png');
  });

  it('DELETE /api/files/:id deletes file record', async () => {
    const uploadRes = await request(app)
      .post('/api/files/upload-request')
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .send({
        filename: 'delete-test.png',
        mimeType: 'image/png',
        sizeBytes: 4096,
      });

    const fileId = uploadRes.body.id;

    await request(app)
      .post(`/api/files/upload/${fileId}`)
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken)
      .attach('file', Buffer.from('fake-image-content'), 'delete-test.png');

    const deleteRes = await request(app)
      .delete(`/api/files/${fileId}`)
      .set('Cookie', sessionCookie)
      .set('x-csrf-token', csrfToken);

    expect(deleteRes.status).toBe(404);
    expect(deleteRes.body.error).toBe('File not found');

    const dbResult = await pool.query('SELECT * FROM files WHERE id = $1', [fileId]);
    expect(dbResult.rows.length).toBe(0);
  });
});

import { beforeAll, afterAll, describe, expect, it } from 'vitest';
import request from 'supertest';
import bcrypt from 'bcryptjs';
import { createApp } from '../app.js';
import { pool } from '../db/client.js';

function getCookiesArray(setCookie: string | string[] | undefined): string[] {
  if (!setCookie) return [];
  return Array.isArray(setCookie) ? setCookie : [setCookie];
}

function cookieHeaderFrom(setCookie: string | string[] | undefined): string {
  return getCookiesArray(setCookie)
    .map((cookie) => cookie.split(';')[0])
    .filter(Boolean)
    .join('; ');
}

describe('Comments API', () => {
  const app = createApp();
  const runId = Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

  let workspaceId: string;
  let authorId: string;
  let adminId: string;
  let otherId: string;
  let documentId: string;
  let authorCookie: string;
  let adminCookie: string;
  let otherCookie: string;

  async function csrfTokenAndCookie(sessionCookie: string) {
    const csrfRes = await request(app).get('/api/csrf-token').set('Cookie', sessionCookie);
    return {
      csrfToken: csrfRes.body.token as string,
      cookie: cookieHeaderFrom(csrfRes.headers['set-cookie']),
    };
  }

  beforeAll(async () => {
    const workspaceRes = await pool.query('INSERT INTO workspaces (name) VALUES ($1) RETURNING id', [
      `Comments Test ${runId}`,
    ]);
    workspaceId = workspaceRes.rows[0].id;

    const authorRes = await pool.query(
      `INSERT INTO users (email, password_hash, name)
       VALUES ($1, $2, $3)
       RETURNING id`,
      [`comments-author-${runId}@ship.local`, await bcrypt.hash('Password123!', 10), 'Comments Author']
    );
    authorId = authorRes.rows[0].id;

    const adminRes = await pool.query(
      `INSERT INTO users (email, password_hash, name)
       VALUES ($1, $2, $3)
       RETURNING id`,
      [`comments-admin-${runId}@ship.local`, await bcrypt.hash('Password123!', 10), 'Comments Admin']
    );
    adminId = adminRes.rows[0].id;

    const otherRes = await pool.query(
      `INSERT INTO users (email, password_hash, name)
       VALUES ($1, $2, $3)
       RETURNING id`,
      [`comments-other-${runId}@ship.local`, await bcrypt.hash('Password123!', 10), 'Comments Other']
    );
    otherId = otherRes.rows[0].id;

    await pool.query(
      `INSERT INTO workspace_memberships (workspace_id, user_id, role) VALUES ($1, $2, 'member'), ($1, $3, 'admin'), ($1, $4, 'member')`,
      [workspaceId, authorId, adminId, otherId]
    );

    const docRes = await pool.query(
      `INSERT INTO documents (workspace_id, document_type, title, content)
       VALUES ($1, 'wiki', 'Comments Doc', '{}'::jsonb)
       RETURNING id`,
      [workspaceId]
    );
    documentId = docRes.rows[0].id;

    const authorLogin = await request(app).post('/api/auth/login').send({ email: `comments-author-${runId}@ship.local`, password: 'Password123!' });
    authorCookie = cookieHeaderFrom(authorLogin.headers['set-cookie']);
    const adminLogin = await request(app).post('/api/auth/login').send({ email: `comments-admin-${runId}@ship.local`, password: 'Password123!' });
    adminCookie = cookieHeaderFrom(adminLogin.headers['set-cookie']);
    const otherLogin = await request(app).post('/api/auth/login').send({ email: `comments-other-${runId}@ship.local`, password: 'Password123!' });
    otherCookie = cookieHeaderFrom(otherLogin.headers['set-cookie']);
  });

  afterAll(async () => {
    await pool.query('DELETE FROM comments WHERE document_id = $1 OR author_id IN ($2, $3, $4)', [documentId, authorId, adminId, otherId]);
    await pool.query('DELETE FROM documents WHERE id = $1', [documentId]);
    await pool.query('DELETE FROM sessions WHERE user_id IN ($1, $2, $3)', [authorId, adminId, otherId]);
    await pool.query('DELETE FROM workspace_memberships WHERE workspace_id = $1', [workspaceId]);
    await pool.query('DELETE FROM users WHERE id IN ($1, $2, $3)', [authorId, adminId, otherId]);
    await pool.query('DELETE FROM workspaces WHERE id = $1', [workspaceId]);
  });

  it('creates comment threads, replies, resolves, persists resolved_at, and enforces deletion permissions', async () => {
    const rootAuth = await csrfTokenAndCookie(authorCookie);
    const rootRes = await request(app)
      .post(`/api/documents/${documentId}/comments`)
      .set('Cookie', authorCookie)
      .set('x-csrf-token', rootAuth.csrfToken)
      .send({ content: 'Root thread' });
    expect(rootRes.status).toBe(201);
    expect(rootRes.body).toMatchObject({
      comment: expect.objectContaining({
        id: expect.any(String),
        document_id: documentId,
        comment_id: expect.any(String),
        parent_id: null,
        author_id: authorId,
        content: 'Root thread',
        resolved_at: null,
        resolved_by: null,
        deleted_at: null,
      }),
    });
    const rootComment = rootRes.body.comment;

    const replyAuth = await csrfTokenAndCookie(otherCookie);
    const replyRes = await request(app)
      .post(`/api/documents/${documentId}/comments`)
      .set('Cookie', otherCookie)
      .set('x-csrf-token', replyAuth.csrfToken)
      .send({ content: 'Reply text', parent_id: rootComment.id, comment_id: rootComment.comment_id });
    expect(replyRes.status).toBe(201);
    expect(replyRes.body).toMatchObject({
      parent_id: rootComment.id,
      comment_id: rootComment.comment_id,
      author_id: otherId,
      content: 'Reply text',
      resolved_at: null,
      resolved_by: null,
      deleted_at: null,
    });

    const listRes = await request(app).get(`/api/documents/${documentId}/comments`).set('Cookie', authorCookie);
    expect(listRes.status).toBe(200);
    expect(listRes.body.comments).toHaveLength(1);
    expect(listRes.body.comments[0].replies).toHaveLength(1);

    const resolveAsOther = await request(app).post(`/api/comments/${rootComment.id}/resolve`).set('Cookie', otherCookie);
    expect(resolveAsOther.status).toBe(403);

    const resolveRes = await request(app).post(`/api/comments/${rootComment.id}/resolve`).set('Cookie', adminCookie);
    expect(resolveRes.status).toBe(200);
    expect(resolveRes.body).toMatchObject({
      id: rootComment.id,
      resolved_at: expect.any(String),
      resolved_by: adminId,
    });

    const resolvedRow = await pool.query('SELECT resolved_at, resolved_by FROM comments WHERE id = $1', [rootComment.id]);
    expect(resolvedRow.rows[0].resolved_at).toBeTruthy();
    expect(resolvedRow.rows[0].resolved_by).toBe(adminId);

    const deleteReplyRes = await request(app).delete(`/api/comments/${replyRes.body.id}`).set('Cookie', otherCookie);
    expect(deleteReplyRes.status).toBe(204);

    const replyDeletedRow = await pool.query('SELECT deleted_at FROM comments WHERE id = $1', [replyRes.body.id]);
    expect(replyDeletedRow.rows[0].deleted_at).toBeTruthy();

    const otherDeleteAttempt = await request(app).delete(`/api/comments/${rootComment.id}`).set('Cookie', otherCookie);
    expect(otherDeleteAttempt.status).toBe(403);
    expect(otherDeleteAttempt.body.error).toBe('Only the author or an admin can delete this comment');

    const deletedByAuthor = await request(app).delete(`/api/comments/${rootComment.id}`).set('Cookie', authorCookie);
    expect(deletedByAuthor.status).toBe(204);

    const deletedRow = await pool.query('SELECT deleted_at FROM comments WHERE id = $1', [rootComment.id]);
    expect(deletedRow.rows[0].deleted_at).toBeTruthy();
  });
});

