    16	  }
    17	}
    18	
    19	// Hash a token for comparison
    20	function hashToken(token: string): string {
    21	  return crypto.createHash('sha256').update(token).digest('hex');
    22	}
    23	
    24	// Validate API token and return user info if valid
    25	async function validateApiToken(token: string): Promise<{
    26	  userId: string;
    27	  workspaceId: string;
    28	  isSuperAdmin: boolean;
    29	  tokenId: string;
    30	} | null> {
    31	  const tokenHash = hashToken(token);
    32	
    33	  const result = await pool.query(
    34	    `SELECT t.id, t.user_id, t.workspace_id, t.expires_at, t.revoked_at, u.is_super_admin
    35	     FROM api_tokens t
    36	     JOIN users u ON t.user_id = u.id
    37	     WHERE t.token_hash = $1`,
    38	    [tokenHash]
    39	  );
    40	
    41	  const tokenRow = result.rows[0];
    42	
    43	  if (!tokenRow) return null;
    44	
    45	  // Check if revoked
    46	  if (tokenRow.revoked_at) return null;
    47	
    48	  // Check if expired
    49	  if (tokenRow.expires_at && new Date(tokenRow.expires_at) < new Date()) return null;
    50	
    51	  // Update last_used_at
    52	  await pool.query(
    53	    'UPDATE api_tokens SET last_used_at = NOW() WHERE id = $1',
    54	    [tokenRow.id]
    55	  );
    56	
    57	  return {
    58	    userId: tokenRow.user_id,
    59	    workspaceId: tokenRow.workspace_id,
    60	    isSuperAdmin: tokenRow.is_super_admin,
    61	    tokenId: tokenRow.id,
    62	  };
    63	}
    64	
    65	export async function authMiddleware(
    66	  req: Request,
    67	  res: Response,
    68	  next: NextFunction
    69	): Promise<void> {
