    28	  message: string;
    29	}
    30	
    31	const activeUploads = new Map<string, UploadInfo>();
    32	const listeners = new Set<() => void>();
    33	let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;
    34	
    35	function hasWindow(): boolean {
    36	  return typeof window !== 'undefined';
    37	}
    38	
    39	function cloneUpload(upload: UploadInfo): UploadInfo {
    40	  return { ...upload };
    41	}
    42	
    43	function notifyListeners(): void {
    44	  listeners.forEach((listener) => listener());
    45	}
    46	
    47	function getUploadMessage(uploadCount: number): string {
    48	  return uploadCount === 1 ? '1 upload is still in progress.' : `${uploadCount} uploads are still in progress.`;
    49	}
    50	
    51	function syncBeforeUnloadListener(): void {
    52	  if (!hasWindow()) return;
    53	
    54	  if (beforeUnloadListener) {
    55	    window.removeEventListener('beforeunload', beforeUnloadListener);
    56	    beforeUnloadListener = null;
    57	  }
    58	
    59	  if (!hasActiveUploads()) return;
    60	
    61	  beforeUnloadListener = (event: BeforeUnloadEvent) => {
    62	    if (!hasActiveUploads()) return;
    63	    event.preventDefault();
    64	    event.returnValue = getUploadMessage(getUploadCount());
    65	    return event.returnValue;
    66	  };
    67	
    68	  window.addEventListener('beforeunload', beforeUnloadListener);
    69	}
    70	
    71	export function registerUpload(id: string, filename: string): void {
    72	  activeUploads.set(id, { id, filename, progress: 0, active: true });
    73	  syncBeforeUnloadListener();
    74	  notifyListeners();
    75	}
