     4	
     5	export interface UploadInfo {
     6	  id: string;
     7	  filename: string;
     8	  progress: number;
     9	  active: boolean;
    10	}
    11	
    12	export interface UploadTrackerSnapshot {
    13	  uploadCount: number;
    14	  activeUploads: UploadInfo[];
    15	}
    16	
    17	export interface UploadNavigationWarningState extends UploadTrackerSnapshot {
    18	  isBlocked: boolean;
    19	  proceed: () => void;
    20	  stay: () => void;
    21	}
    22	
    23	export interface UploadNavigationWarningViewState extends UploadNavigationWarningState {
    24	  isOpen: boolean;
    25	}
    26	
    27	export interface UploadNavigationWarningHookState extends UploadNavigationWarningViewState {
    28	  message: string;
    29	}
    30	
    31	const activeUploads = new Map<string, UploadInfo>();
    32	const listeners = new Set<() => void>();
    33	let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;
    34	
    35	function hasWindow(): boolean {
    36	  return typeof window !== 'undefined';
    37	}
    38	
    39	function cloneUpload(upload: UploadInfo): UploadInfo {
    40	  return { ...upload };
    41	}
    42	
    43	function notifyListeners(): void {
    44	  listeners.forEach((listener) => listener());
    45	}
    46	
    47	function getUploadMessage(uploadCount: number): string {
    48	  return uploadCount === 1
    49	    ? '1 upload is still in progress.'
    50	    : `${uploadCount} uploads are still in progress.`;
    51	}
    52	
    53	function syncBeforeUnloadListener(): void {
    54	  if (!hasWindow()) return;
    55	
    56	  if (beforeUnloadListener) {
    57	    window.removeEventListener('beforeunload', beforeUnloadListener);
    58	    beforeUnloadListener = null;
    59	  }
    60	
    61	  if (!hasActiveUploads()) return;
    62	
    63	  beforeUnloadListener = (event: BeforeUnloadEvent) => {
    64	    if (!hasActiveUploads()) return;
    65	    event.preventDefault();
    66	    event.returnValue = getUploadMessage(getUploadCount());
    67	    return event.returnValue;
    68	  };
    69	
    70	  window.addEventListener('beforeunload', beforeUnloadListener);
    71	}
    72	
    73	export function registerUpload(id: string, filename: string): void {
    74	  activeUploads.set(id, { id, filename, progress: 0, active: true });
    75	  syncBeforeUnloadListener();
    76	  notifyListeners();
    77	}
    78	
    79	export function updateUploadProgress(id: string, progress: number): void {
    80	  const upload = activeUploads.get(id);
    81	  if (!upload) return;
    82	
    83	  upload.progress = progress;
    84	  upload.active = true;
    85	  syncBeforeUnloadListener();
    86	  notifyListeners();
    87	}
    88	
