    90	  const upload = activeUploads.get(id);
    91	  if (!upload) return;
    92	
    93	  upload.active = false;
    94	  syncBeforeUnloadListener();
    95	  notifyListeners();
    96	}
    97	
    98	export function unregisterUpload(id: string): void {
    99	  activeUploads.delete(id);
   100	  syncBeforeUnloadListener();
   101	  notifyListeners();
   102	}
   103	
   104	export function clearUploads(): void {
   105	  activeUploads.clear();
   106	  syncBeforeUnloadListener();
   107	  notifyListeners();
   108	}
   109	
   110	export function getUploadCount(): number {
   111	  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
   112	}
   113	
   114	export function getActiveUploads(): UploadInfo[] {
   115	  return Array.from(activeUploads.values())
   116	    .filter((upload) => upload.active)
   117	    .map(cloneUpload);
   118	}
   119	
   120	export function hasActiveUploads(): boolean {
   121	  return getUploadCount() > 0;
   122	}
   123	
   124	export function getUploadSnapshot(): UploadTrackerSnapshot {
   125	  return {
   126	    uploadCount: getUploadCount(),
   127	    activeUploads: getActiveUploads(),
   128	  };
   129	}
   130	
   131	export function subscribeToUploads(listener: () => void): () => void {
   132	  listeners.add(listener);
   133	  listener();
   134	  return () => listeners.delete(listener);
   135	}
   136	
   137	export function getUploadNavigationWarningState(): UploadNavigationWarningState {
   138	  const snapshot = getUploadSnapshot();
   139	  return {
   140	    ...snapshot,
   141	    isBlocked: snapshot.uploadCount > 0,
   142	    proceed: clearUploads,
   143	    stay: () => undefined,
   144	  };
   145	}
   146	
   147	export function getUploadNavigationWarningViewState(): UploadNavigationWarningViewState {
   148	  const state = getUploadNavigationWarningState();
   149	  return {
   150	    ...state,
   151	    isOpen: state.isBlocked,
   152	  };
   153	}
   154	
   155	export function getUploadNavigationWarningMessage(uploadCount: number): string {
   156	  return getUploadMessage(uploadCount);
   157	}
   158	
   159	export function getUploadNavigationWarningHookState(): UploadNavigationWarningHookState {
   160	  const state = getUploadNavigationWarningViewState();
   161	  return {
   162	    ...state,
   163	    message: getUploadNavigationWarningMessage(state.uploadCount),
   164	  };
   165	}
