    77	// Simple helpers that return Response objects (for contexts that need res.ok checks)
    78	async function fetchWithCsrf(
    79	  endpoint: string,
    80	  method: 'POST' | 'PUT' | 'PATCH' | 'DELETE',
    81	  body?: object
    82	): Promise<Response> {
    83	  const token = await ensureCsrfToken();
    84	  const res = await fetch(`${API_URL}${endpoint}`, {
    85	    method,
    86	    headers: {
    87	      'Content-Type': 'application/json',
    88	      'X-CSRF-Token': token,
    89	    },
    90	    credentials: 'include',
    91	    body: body ? JSON.stringify(body) : undefined,
    92	  });
    93	
    94	  const isJson = isJsonResponse(res);
    95	
    96	  // CloudFront intercepts 403s and returns HTML - detect and redirect to login
    97	  if (res.status === 403 && !isJson) {
    98	    handleSessionExpired(); // never returns
    99	  }
   100	
   101	  // If CSRF token invalid (403 with JSON), retry once
   102	  if (res.status === 403 && isJson) {
   103	    clearCsrfToken();
   104	    const newToken = await ensureCsrfToken();
   105	    return fetch(`${API_URL}${endpoint}`, {
   106	      method,
   107	      headers: {
   108	        'Content-Type': 'application/json',
   109	        'X-CSRF-Token': newToken,
   110	      },
   111	      credentials: 'include',
   112	      body: body ? JSON.stringify(body) : undefined,
   113	    });
   114	  }
   115	  return res;
   116	}
   117	
   118	export async function apiGet(endpoint: string): Promise<Response> {
   119	  const res = await fetch(`${API_URL}${endpoint}`, {
   120	    credentials: 'include',
   121	  });
   122	
   123	  // Handle session expiration - redirect to login
   124	  if (res.status === 401) {
   125	    handleSessionExpired(); // never returns
   126	  }
   127	
   128	  // Check for non-JSON response (CloudFront HTML interception)
   129	  // This can happen when:
   130	  // 1. CDN serves HTML error page for non-existent routes
   131	  // 2. Session expired and CloudFront returns login page
   132	  // 3. Route misconfiguration serving index.html for API routes
   133	  if (!isJsonResponse(res)) {
   134	    // Non-200 + non-JSON = likely session issue (CloudFront 403 interception)
   135	    if (res.status !== 200) {
   136	      handleSessionExpired(); // never returns
   137	    }
   138	    // 200 + non-JSON = likely routing/CDN misconfiguration
   139	    // Don't redirect to login (not a session issue), throw error for React Query to handle
   140	    throw new Error(`API returned HTML instead of JSON for ${endpoint}. This may indicate a routing or CDN configuration issue.`);
   141	  }
   142	
   143	  return res;
   144	}
