   543	/** Get MIME type from filename extension as fallback */
   544	export function getMimeTypeFromExtension(filename: string): string | null {
   545	  const ext = filename.toLowerCase().slice(filename.lastIndexOf("."));
   546	  return EXTENSION_TO_MIME[ext] || null;
