   549	/** Check if a file type is allowed for upload */
   550	export function isAllowedFileType(
   551	  mimeType: string,
   552	  filename?: string,
   553	): boolean {
   554	  if (!filename) return true;
   555	  const ext = filename.toLowerCase().slice(filename.lastIndexOf("."));
   556	  if (BLOCKED_EXTENSIONS.has(ext)) return false;
   557	  return true;
