   560	/** Check if a file is an image */
   561	export function isImageFile(mimeType: string, filename?: string): boolean {
   562	  if (mimeType.startsWith("image/")) return true;
   563	  if (!filename) return false;
   564	  const ext = filename.toLowerCase().slice(filename.lastIndexOf("."));
   565	  return [".jpg", ".jpeg", ".png", ".gif", ".webp", ".svg"].includes(ext);
