     2	 * Upload Context - Tracks active uploads for navigation warnings
     3	 * Subscribes to the global upload tracker for real-time updates
     4	 */
     5	import { createContext, useContext, ReactNode, useCallback, useMemo, useSyncExternalStore } from 'react';
     6	import { clearUploads, getUploadSnapshot, subscribeToUploads } from '@/services/uploadTracker';
     7	import type { UploadNavigationWarningState, UploadTrackerSnapshot } from '@/services/uploadTracker';
     8	
     9	interface UploadContextValue extends UploadTrackerSnapshot {
    10	  isUploading: boolean;
    11	  clearUploads: () => void;
    12	}
    13	
    14	const UploadContext = createContext<UploadContextValue | null>(null);
    15	
    16	export function UploadProvider({ children }: { children: ReactNode }) {
    17	  const snapshot = useSyncExternalStore(subscribeToUploads, getUploadSnapshot, getUploadSnapshot);
    18	  const isUploading = snapshot.uploadCount > 0;
    19	
    20	  const clearTrackedUploads = useCallback(() => {
    21	    clearUploads();
    22	  }, []);
    23	
    24	  const value = useMemo<UploadContextValue>(
    25	    () => ({
    26	      ...snapshot,
    27	      isUploading,
    28	      clearUploads: clearTrackedUploads,
    29	    }),
    30	    [snapshot, isUploading, clearTrackedUploads]
    31	  );
    32	
    33	  return <UploadContext.Provider value={value}>{children}</UploadContext.Provider>;
    34	}
    35	
    36	export function useUploads() {
    37	  const context = useContext(UploadContext);
    38	  if (!context) {
    39	    throw new Error('useUploads must be used within an UploadProvider');
    40	  }
    41	  return context;
    42	}
    43	
    44	export function useUploadNavigationWarning(): UploadNavigationWarningState {
    45	  const { isUploading, uploadCount, activeUploads, clearUploads } = useUploads();
    46	
    47	  const proceed = useCallback(() => {
    48	    clearUploads();
    49	  }, [clearUploads]);
    50	
    51	  const stay = useCallback(() => undefined, []);
    52	
    53	  return {
    54	    isBlocked: isUploading,
    55	    uploadCount,
    56	    activeUploads,
    57	    proceed,
    58	    stay,
    59	  };
    60	}
