    81	// Hook to create document with optimistic update
    82	export function useCreateDocument() {
    83	  const queryClient = useQueryClient();
    84	
    85	  return useMutation({
    86	    mutationFn: (data: { title?: string; document_type?: string; parent_id?: string | null; visibility?: 'private' | 'workspace' }) =>
    87	      createDocumentApi({
    88	        title: data.title ?? 'Untitled',
    89	        document_type: data.document_type ?? 'wiki',
    90	        parent_id: data.parent_id ?? null,
    91	      }),
    92	    onMutate: async (newDoc) => {
    93	      await queryClient.cancelQueries({ queryKey: documentKeys.lists() });
    94	      const previousDocs = queryClient.getQueryData<WikiDocument[]>(documentKeys.wikiList());
    95	
    96	      const optimisticDoc: WikiDocument = {
    97	        id: `temp-${crypto.randomUUID()}`,
    98	        title: newDoc.title ?? 'Untitled',
    99	        document_type: newDoc.document_type ?? 'wiki',
   100	        parent_id: newDoc.parent_id ?? null,
   101	        position: 0,
   102	        created_at: new Date().toISOString(),
   103	        updated_at: new Date().toISOString(),
   104	        visibility: newDoc.visibility ?? 'workspace',
   105	      };
   106	
   107	      queryClient.setQueryData<WikiDocument[]>(
   108	        documentKeys.wikiList(),
   109	        (old) => [optimisticDoc, ...(old || [])]
   110	      );
   111	
   112	      return { previousDocs, optimisticId: optimisticDoc.id };
   113	    },
   114	    onError: (_err, _newDoc, context) => {
   115	      if (context?.previousDocs) {
   116	        queryClient.setQueryData(documentKeys.wikiList(), context.previousDocs);
   117	      }
   118	    },
   119	    onSuccess: (data, _variables, context) => {
   120	      if (context?.optimisticId) {
   121	        queryClient.setQueryData<WikiDocument[]>(
   122	          documentKeys.wikiList(),
   123	          (old) => old?.map(d => d.id === context.optimisticId ? data : d) || [data]
   124	        );
   125	      }
   126	    },
   127	    onSettled: () => {
   128	      queryClient.invalidateQueries({ queryKey: documentKeys.lists() });
   129	    },
   130	  });
   131	}
   132	
   133	// Hook to update document with optimistic update
   134	export function useUpdateDocument() {
   135	  const queryClient = useQueryClient();
   136	
   137	  return useMutation({
   138	    mutationFn: ({ id, updates }: { id: string; updates: Partial<WikiDocument> }) =>
   139	      updateDocumentApi(id, updates),
   140	    onMutate: async ({ id, updates }) => {
   141	      await queryClient.cancelQueries({ queryKey: documentKeys.lists() });
   142	      const previousDocs = queryClient.getQueryData<WikiDocument[]>(documentKeys.wikiList());
   143	
   144	      queryClient.setQueryData<WikiDocument[]>(
   145	        documentKeys.wikiList(),
   146	        (old) => old?.map(d => d.id === id ? { ...d, ...updates } : d) || []
   147	      );
   148	
   149	      return { previousDocs };
   150	    },
   151	    onError: (_err, _variables, context) => {
   152	      if (context?.previousDocs) {
   153	        queryClient.setQueryData(documentKeys.wikiList(), context.previousDocs);
   154	      }
   155	    },
   156	    onSuccess: (data, { id }) => {
   157	      queryClient.setQueryData<WikiDocument[]>(
   158	        documentKeys.wikiList(),
   159	        (old) => old?.map(d => d.id === id ? data : d) || []
   160	      );
   161	    },
   162	    onSettled: () => {
   163	      queryClient.invalidateQueries({ queryKey: documentKeys.lists() });
   164	    },
   165	  });
   166	}
