    14	// CSRF token cache for state-changing requests
    15	let csrfToken: string | null = null;
    16	
    17	// Helper: Check if response has JSON content type
    18	function isJsonResponse(response: Response): boolean {
    19	  const contentType = response.headers.get('content-type');
    20	  return contentType?.includes('application/json') ?? false;
    21	}
    22	
    23	/**
    24	 * Handle session expiration - redirect to login with expired=true flag
    25	 *
    26	 * IMPORTANT: Only call this for actual session expiration (SESSION_EXPIRED error code),
    27	 * NOT for missing sessions (UNAUTHORIZED). Fresh visitors with no session should get
    28	 * a clean redirect via ProtectedRoute without the "session expired" message.
    29	 *
    30	 * The expired=true flag triggers the yellow "session expired" modal on the login page.
    31	 * Fresh visitors shouldn't see this - it would be confusing UX.
    32	 *
    33	 * Returns `never` because it always redirects or throws.
    34	 */
    35	function handleSessionExpired(): never {
    36	  // Don't redirect to login when offline - let TanStack Query handle retries
    37	  if (!navigator.onLine) {
    38	    throw new Error('Network offline - request failed');
    39	  }
    40	  // Don't redirect on public routes like /invite - they work without authentication
    41	  if (window.location.pathname.startsWith('/invite')) {
    42	    throw new Error('Session check failed - continuing on public route');
    43	  }
    44	  if (window.location.pathname !== '/login') {
    45	    const returnTo = encodeURIComponent(
    46	      window.location.pathname + window.location.search + window.location.hash
    47	    );
    48	    window.location.href = `/login?expired=true&returnTo=${returnTo}`;
    49	  }
    50	  // Throw to satisfy TypeScript's `never` type (redirect is async)
    51	  throw new Error('Session expired - redirecting to login');
    52	}
    53	
    54	async function ensureCsrfToken(): Promise<string> {
    55	  if (!csrfToken) {
    56	    const response = await fetch(`${API_URL}/api/csrf-token`, {
    57	      credentials: 'include',
    58	    });
    59	    if (!response.ok || !isJsonResponse(response)) {
    60	      // Session likely expired - redirect to login
    61	      if (response.status === 401 || response.status === 403) {
    62	        handleSessionExpired(); // never returns
    63	      }
    64	      throw new Error('Failed to get CSRF token');
    65	    }
    66	    const data = await response.json();
    67	    csrfToken = data.token;
    68	  }
    69	  return csrfToken!;
    70	}
    71	
    72	// Clear CSRF token on logout or session change
    73	export function clearCsrfToken(): void {
    74	  csrfToken = null;
    75	}
    76	
    77	// Simple helpers that return Response objects (for contexts that need res.ok checks)
    78	async function fetchWithCsrf(
    79	  endpoint: string,
    80	  method: 'POST' | 'PUT' | 'PATCH' | 'DELETE',
    81	  body?: object
    82	): Promise<Response> {
    83	  const token = await ensureCsrfToken();
    84	  const res = await fetch(`${API_URL}${endpoint}`, {
    85	    method,
    86	    headers: {
    87	      'Content-Type': 'application/json',
    88	      'X-CSRF-Token': token,
    89	    },
    90	    credentials: 'include',
    91	    body: body ? JSON.stringify(body) : undefined,
    92	  });
    93	
    94	  const isJson = isJsonResponse(res);
    95	
    96	  // CloudFront intercepts 403s and returns HTML - detect and redirect to login
    97	  if (res.status === 403 && !isJson) {
    98	    handleSessionExpired(); // never returns
    99	  }
   100	
   101	  // If CSRF token invalid (403 with JSON), retry once
   102	  if (res.status === 403 && isJson) {
   103	    clearCsrfToken();
   104	    const newToken = await ensureCsrfToken();
   105	    return fetch(`${API_URL}${endpoint}`, {
   106	      method,
   107	      headers: {
   108	        'Content-Type': 'application/json',
   109	        'X-CSRF-Token': newToken,
   110	      },
   111	      credentials: 'include',
   112	      body: body ? JSON.stringify(body) : undefined,
   113	    });
   114	  }
   115	  return res;
   116	}
