import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';

import { apiDelete, apiGet, apiPatch, apiPost } from '@/lib/api';

export type CommentStatus = 'open' | 'resolved' | 'deleted';

export interface CommentUser {
  id: string;
  name?: string | null;
  email?: string | null;
  avatarUrl?: string | null;
}

export interface CommentThread {
  id: string;
  postId: string;
  parentId: string | null;
  content: string;
  status: CommentStatus;
  createdAt: string;
  updatedAt: string;
  resolvedAt?: string | null;
  resolvedById?: string | null;
  author?: CommentUser | null;
  replies?: CommentThread[];
}

export interface CommentsThreadListResponse {
  threads: CommentThread[];
}

export interface CreateCommentInput {
  postId: string;
  content: string;
  parentId?: string | null;
}

export interface UpdateCommentInput {
  content: string;
}

export interface ResolveCommentInput {
  resolved: boolean;
}

const COMMENTS_QUERY_KEY = ['comments'] as const;

const commentsKey = (postId: string) => [...COMMENTS_QUERY_KEY, postId] as const;

async function fetchCommentThreads(postId: string): Promise<CommentThread[]> {
  const response = await apiGet(`/api/posts/${postId}/comments`);
  if (!response.ok) {
    const error = new Error('Failed to fetch comments') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
  const data = (await response.json()) as CommentsThreadListResponse;
  return data.threads;
}

async function createComment(input: CreateCommentInput): Promise<CommentThread> {
  const response = await apiPost(`/api/posts/${input.postId}/comments`, {
    content: input.content,
    parentId: input.parentId ?? null,
  });
  if (!response.ok) {
    const error = new Error('Failed to create comment') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
  return response.json();
}

async function replyToComment(commentId: string, content: string): Promise<CommentThread> {
  const response = await apiPost(`/api/comments/${commentId}/replies`, { content });
  if (!response.ok) {
    const error = new Error('Failed to create reply') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
  return response.json();
}

async function updateComment(commentId: string, content: string): Promise<CommentThread> {
  const response = await apiPatch(`/api/comments/${commentId}`, { content });
  if (!response.ok) {
    const error = new Error('Failed to update comment') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
  return response.json();
}

async function resolveComment(commentId: string, resolved: boolean): Promise<CommentThread> {
  const response = await apiPatch(`/api/comments/${commentId}/resolve`, { resolved });
  if (!response.ok) {
    const error = new Error('Failed to resolve comment') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
  return response.json();
}

async function deleteComment(commentId: string): Promise<void> {
  const response = await apiDelete(`/api/comments/${commentId}`);
  if (!response.ok) {
    const error = new Error('Failed to delete comment') as Error & { status: number };
    error.status = response.status;
    throw error;
  }
}

function upsertThread(threads: CommentThread[], thread: CommentThread): CommentThread[] {
  const idx = threads.findIndex((t) => t.id === thread.id);
  if (idx === -1) return [thread, ...threads];
  return threads.map((t) => (t.id === thread.id ? thread : t));
}

function removeThread(threads: CommentThread[], commentId: string): CommentThread[] {
  return threads.filter((t) => t.id !== commentId);
}

export function useCommentsQuery(postId?: string) {
  const queryClient = useQueryClient();
  const key = postId ? commentsKey(postId) : commentsKey('__disabled__');

  const commentsQuery = useQuery({
    queryKey: key,
    queryFn: () => {
      if (!postId) throw new Error('postId is required');
      return fetchCommentThreads(postId);
    },
    enabled: Boolean(postId),
  });

  const createMutation = useMutation({
    mutationFn: createComment,
    onSuccess: async (created, variables) => {
      await queryClient.cancelQueries({ queryKey: commentsKey(variables.postId) });
      queryClient.setQueryData<CommentThread[]>(commentsKey(variables.postId), (old = []) => upsertThread(old, created));
      await queryClient.invalidateQueries({ queryKey: commentsKey(variables.postId) });
    },
  });

  const replyMutation = useMutation({
    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => replyToComment(commentId, content),
    onSuccess: async (reply) => {
      if (!postId) return;
      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, reply));
      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => updateComment(commentId, content),
    onSuccess: async (updated) => {
      if (!postId) return;
      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, updated));
      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
    },
  });

  const resolveMutation = useMutation({
    mutationFn: ({ commentId, resolved }: { commentId: string; resolved: boolean }) => resolveComment(commentId, resolved),
    onSuccess: async (updated) => {
      if (!postId) return;
      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, updated));
      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: deleteComment,
    onSuccess: async (_void, commentId) => {
      if (!postId) return;
      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => removeThread(old, commentId));
      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
    },
  });

  return {
    ...commentsQuery,
    comments: commentsQuery.data ?? [],
    createComment: createMutation.mutateAsync,
    replyToComment: replyMutation.mutateAsync,
    updateComment: updateMutation.mutateAsync,
    resolveComment: resolveMutation.mutateAsync,
    deleteComment: deleteMutation.mutateAsync,
    isCreatingComment: createMutation.isPending,
    isReplyingToComment: replyMutation.isPending,
    isUpdatingComment: updateMutation.isPending,
    isResolvingComment: resolveMutation.isPending,
    isDeletingComment: deleteMutation.isPending,
  };
}

