tool_input.new_string:
import { useSyncExternalStore } from "react";

import {
  getUploadNavigationWarningHookState,
  subscribeToUploads,
} from "../services/uploadTracker.js";

export function useUploadNavigationWarning() {
  return useSyncExternalStore(
    subscribeToUploads,
    getUploadNavigationWarningHookState,
    getUploadNavigationWarningHookState,
  );
}

export function UploadNavigationWarning() {
  const state = useUploadNavigationWarning();

  if (!state.isOpen) return null;

  return (
    <div
      role="alertdialog"
      aria-modal="true"
      aria-labelledby="upload-warning-title"
      aria-describedby="upload-warning-message"
      style={{
        position: "fixed",
        inset: 0,
        display: "grid",
        placeItems: "center",
        background: "rgba(15, 23, 42, 0.45)",
        zIndex: 50,
      }}
    >
      <div
        style={{
          width: "min(92vw, 28rem)",
          background: "white",
          borderRadius: "0.75rem",
          padding: "1.25rem",
          boxShadow: "0 20px 40px rgba(15, 23, 42, 0.2)",
        }}
      >
        <h2 id="upload-warning-title" style={{ marginTop: 0 }}>
          Uploads in progress
        </h2>
        <p id="upload-warning-message">{state.message}</p>
        <div style={{ display: "flex", gap: "0.75rem", justifyContent: "flex-end" }}>
          <button type="button" onClick={state.stay}>
            Stay on page
          </button>
          <button type="button" onClick={state.proceed}>
            Leave anyway
          </button>
        </div>
      </div>
    </div>
  );
}

export { subscribeToUploads } from "../services/uploadTracker.js";

