import { Router, Request, Response } from 'express';
import { randomUUID } from 'crypto';
import { basename, extname, join } from 'path';
import { mkdirSync, writeFileSync } from 'fs';
import { z } from 'zod';
import { S3Client, GetObjectCommand, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';
import { getAppEnvConfig } from '../config/env.js';

const router = Router();

const MAX_FILE_SIZE_BYTES = 1024 * 1024 * 1024;
const DEFAULT_UPLOAD_URL_EXPIRES_SECONDS = 15 * 60;
const BLOCKED_EXTENSIONS = new Set([
  '.exe', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif', '.vbs', '.vbe', '.js', '.jse', '.ws', '.wsf', '.wsc', '.wsh',
  '.dll', '.sys', '.drv', '.cpl', '.ocx', '.lnk', '.inf', '.reg', '.msc', '.app', '.dmg', '.pkg', '.sh', '.bash', '.deb',
  '.rpm', '.run', '.jar', '.ps1', '.psm1', '.psd1',
]);

const fileIdSchema = z.string().uuid();
const uploadRequestSchema = z.object({
  filename: z.string().min(1).max(255),
  mimeType: z.string().min(1).max(100),
  sizeBytes: z.coerce.number().int().positive().max(MAX_FILE_SIZE_BYTES),
});

const multipartFileSchema = z.object({
  originalname: z.string().min(1),
  mimetype: z.string().min(1),
  buffer: z.instanceof(Buffer),
  size: z.number().int().nonnegative(),
});

type UploadedFileRecord = {
  id: string;
  filename: string;
  mime_type: string;
  size_bytes: number;
  status: string;
  created_at: string;
  uploaded_at: string | null;
  failed_at: string | null;
  error_message: string | null;
  s3_key: string;
};

const {
  s3UploadsBucket,
  s3UploadsRegion,
  uploadsBaseUrl,
  uploadUrlExpiresInSeconds,
  uploadMaxBytes,
  localUploadsPath,
} = getAppEnvConfig();
const s3BucketName = s3UploadsBucket || null;
const awsRegion = s3UploadsRegion || 'us-east-1';
const presignedUrlExpiresInSeconds = uploadUrlExpiresInSeconds || DEFAULT_UPLOAD_URL_EXPIRES_SECONDS;
const localUploadRoot = localUploadsPath;

function getFileStorageKey(fileId: string, filename: string): string {
  return `${fileId}${extname(basename(filename))}`;
}

function getLocalDownloadUrl(fileId: string, filename: string): string {
  return `${uploadsBaseUrl.replace(/\/$/, '')}/${getFileStorageKey(fileId, filename)}`;
}

function isDangerousFilename(filename: string): boolean {
  const clean = basename(filename).toLowerCase();
  const extension = extname(clean);
  return extension !== '' && BLOCKED_EXTENSIONS.has(extension);
}

function getMultipartFile(req: Request): { buffer: Buffer; filename: string; mimeType: string; sizeBytes: number } {
  const anyReq = req as Request & { file?: unknown; files?: unknown };
  const candidate = anyReq.file ?? (Array.isArray(anyReq.files) ? anyReq.files[0] : undefined);
  const parsed = multipartFileSchema.safeParse(candidate);
  if (!parsed.success) {
    throw new Error('No uploaded file found');
  }
  return {
    buffer: parsed.data.buffer,
    filename: parsed.data.originalname,
    mimeType: parsed.data.mimetype,
    sizeBytes: parsed.data.size,
  };
}

function getS3Client(): S3Client {
  return new S3Client({ region: awsRegion });
}

async function createPresignedUploadUrl(key: string, mimeType: string, sizeBytes: number): Promise<string> {
  return getSignedUrl(getS3Client(), new PutObjectCommand({ Bucket: s3BucketName!, Key: key, ContentType: mimeType, ContentLength: sizeBytes }), {
    expiresIn: presignedUrlExpiresInSeconds,
  });
}

async function createPresignedDownloadUrl(key: string): Promise<string> {
  return getSignedUrl(getS3Client(), new GetObjectCommand({ Bucket: s3BucketName!, Key: key }), {
    expiresIn: presignedUrlExpiresInSeconds,
  });
}

function toFileResponse(file: UploadedFileRecord, downloadUrl: string) {
  return {
    id: file.id,
    filename: file.filename,
    mimeType: file.mime_type,
    sizeBytes: Number(file.size_bytes),
    status: file.status,
    createdAt: file.created_at,
    uploadedAt: file.uploaded_at,
    failedAt: file.failed_at,
    errorMessage: file.error_message,
    downloadUrl,
  };
}

router.post('/upload-request', authMiddleware, async (req: Request, res: Response) => {
  const parsed = uploadRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid input', details: parsed.error.flatten() });
    return;
  }

  const { filename, mimeType, sizeBytes } = parsed.data;
  if (isDangerousFilename(filename)) {
    res.status(400).json({ error: 'File type not allowed' });
    return;
  }

  const fileId = randomUUID();
  const storageKey = getFileStorageKey(fileId, filename);
  await pool.query(
    `INSERT INTO files (id, workspace_id, uploaded_by, filename, mime_type, size_bytes, s3_key, status)
     VALUES ($1, $2, $3, $4, $5, $6, $7, 'pending')`,
    [fileId, req.workspaceId, req.userId, filename, mimeType, sizeBytes, storageKey]
  );

  if (s3BucketName) {
    const uploadUrl = await createPresignedUploadUrl(storageKey, mimeType, sizeBytes);
    res.status(201).json({
      id: fileId,
      filename,
      mimeType,
      sizeBytes,
      status: 'pending',
      uploadType: 's3',
      uploadUrl,
      method: 'PUT',
      expiresInSeconds: presignedUrlExpiresInSeconds,
      storageKey,
      uploadEndpoint: null,
      downloadUrl: null,
    });
    return;
  }

  res.status(201).json({
    id: fileId,
    filename,
    mimeType,
    sizeBytes,
    status: 'pending',
    uploadType: 'local',
    uploadUrl: null,
    method: 'POST',
    expiresInSeconds: null,
    storageKey,
    uploadEndpoint: `/api/files/upload/${fileId}`,
    downloadUrl: null,
  });
});

router.post('/upload/:id', authMiddleware, async (req: Request, res: Response) => {
  const parsed = fileIdSchema.safeParse(req.params.id);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }
  if (s3BucketName) {
    res.status(400).json({ error: 'Local upload endpoint is disabled when S3 storage is enabled' });
    return;
  }

  const fileResult = await pool.query(
    `SELECT id, filename, mime_type, size_bytes, s3_key, status
     FROM files WHERE id = $1 AND workspace_id = $2`,
    [parsed.data, req.workspaceId]
  );
  const file = fileResult.rows[0] as UploadedFileRecord | undefined;
  if (!file) {
    res.status(404).json({ error: 'File not found' });
    return;
  }
  if (file.status !== 'pending') {
    res.status(409).json({ error: 'File has already been uploaded' });
    return;
  }

  let multipart;
  try {
    multipart = getMultipartFile(req);
  } catch {
    res.status(400).json({ error: 'No uploaded file found' });
    return;
  }
  if (multipart.sizeBytes > uploadMaxBytes) {
    res.status(413).json({ error: 'File exceeds 1GB limit' });
    return;
  }

  mkdirSync(localUploadRoot, { recursive: true });
  writeFileSync(join(localUploadRoot, file.s3_key), multipart.buffer);
  await pool.query(
    `UPDATE files SET status = 'uploaded', uploaded_at = now(), error_message = NULL WHERE id = $1 AND workspace_id = $2`,
    [parsed.data, req.workspaceId]
  );

  res.status(200).json({
    id: file.id,
    filename: file.filename,
    mimeType: file.mime_type,
    sizeBytes: Number(file.size_bytes),
    status: 'uploaded',
    downloadUrl: getLocalDownloadUrl(file.id, file.filename),
  });
});

router.get('/:id', authMiddleware, async (req: Request, res: Response) => {
  const parsed = fileIdSchema.safeParse(req.params.id);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }

  const result = await pool.query(
    `SELECT id, filename, mime_type, size_bytes, status, created_at, uploaded_at, failed_at, error_message, s3_key
     FROM files
     WHERE id = $1 AND workspace_id = $2`,
    [parsed.data, req.workspaceId]
  );
  const file = result.rows[0] as UploadedFileRecord | undefined;
  if (!file) {
    res.status(404).json({ error: 'File not found' });
    return;
  }

  const downloadUrl = s3BucketName ? await createPresignedDownloadUrl(file.s3_key) : getLocalDownloadUrl(file.id, file.filename);
  res.json(toFileResponse(file, downloadUrl));
});

export function registerLocalUploadsStatic(_app: { use: (...args: any[]) => unknown }, _staticMiddleware?: unknown): void {
  // Static serving is wired from the server bootstrap so local uploads can be exposed
  // only in local-dev style configurations.
}

export { router as filesRouter };

