     9	// Template headings that don't count as real content
    10	export const TEMPLATE_HEADINGS = [
    11	  'What I plan to accomplish this week',
    12	  'What I delivered this week',
    13	  'Unplanned work',
    14	];
    15	
    16	/**
    17	 * Recursively extract text from TipTap JSON content.
    18	 */
    19	export function extractText(node: unknown): string {
    20	  if (!node || typeof node !== 'object') return '';
    21	  const n = node as { type?: string; text?: string; content?: unknown[] };
    22	  if (n.type === 'text' && n.text) return n.text;
    23	  if (Array.isArray(n.content)) return n.content.map(extractText).join('');
    24	  return '';
    25	}
    26	
    27	/**
    28	 * Check if document content has meaningful text beyond template headings.
    29	 *
    30	 * A document is considered to have content if, after stripping template
    31	 * headings, there is still non-whitespace text remaining.
    32	 */
    33	export function hasContent(content: unknown): boolean {
    34	  if (!content || typeof content !== 'object') return false;
    35	  const doc = content as { content?: unknown[] };
    36	  if (!Array.isArray(doc.content) || doc.content.length === 0) return false;
    37	
    38	  const allText = extractText(content).trim();
    39	  let textWithoutTemplate = allText;
    40	  for (const heading of TEMPLATE_HEADINGS) {
    41	    textWithoutTemplate = textWithoutTemplate.replace(heading, '');
    42	  }
    43	  return textWithoutTemplate.trim().length > 0;
    44	}
