import { Router, type Request, type Response } from 'express';
import { z } from 'zod';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const router = Router();

const uuidParamSchema = z.string().uuid();
const documentLinkSyncSchema = z.object({
  target_ids: z.array(z.string().uuid()).default([]),
  links: z.array(z.string().uuid()).default([]),
  mentions: z.array(z.string().uuid()).default([]),
  extracted_links: z.array(z.string().uuid()).default([]),
  extracted_mentions: z.array(z.string().uuid()).default([]),
});

type BacklinkSummary = {
  id: string;
  title: string;
  document_type: string;
};

type LinkSyncResponse = {
  success: boolean;
  document_id: string;
  linked_document_ids: string[];
};

function buildSyncedLinkSet(payload: z.infer<typeof documentLinkSyncSchema>) {
  return Array.from(
    new Set([
      ...(payload.target_ids ?? []),
      ...(payload.links ?? []),
      ...(payload.mentions ?? []),
      ...(payload.extracted_links ?? []),
      ...(payload.extracted_mentions ?? []),
    ])
  );
}

async function ensureDocumentExistsForWorkspace(docId: string, workspaceId: string) {
  const result = await pool.query(
    `SELECT id FROM documents
     WHERE id = $1
       AND workspace_id = $2
       AND deleted_at IS NULL`,
    [docId, workspaceId]
  );

  return result.rows.length > 0;
}

router.get('/:id/backlinks', authMiddleware, async (req: Request, res: Response) => {
  const parsedId = uuidParamSchema.safeParse(req.params.id);
  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });

  const workspaceId = req.workspaceId;
  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });

  const documentExists = await ensureDocumentExistsForWorkspace(parsedId.data, workspaceId);
  if (!documentExists) return res.status(404).json({ error: 'Document not found' });

  const result = await pool.query(
    `SELECT d.id, d.document_type, d.title
     FROM document_links dl
     JOIN documents d ON dl.source_id = d.id
     WHERE dl.target_id = $1
       AND d.workspace_id = $2
       AND d.deleted_at IS NULL
       AND d.archived_at IS NULL
     ORDER BY dl.created_at DESC, d.created_at DESC`,
    [parsedId.data, workspaceId]
  );

  return res.json(
    result.rows.map((row) => ({
      id: row.id,
      title: row.title,
      document_type: row.document_type,
    })) as BacklinkSummary[]
  );
});

router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
  const parsedId = uuidParamSchema.safeParse(req.params.id);
  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });

  const workspaceId = req.workspaceId;
  if (!workspaceId) return res.status(401).json({ error: 'Unauthorized' });

  const payload = req.body as unknown;
  const parsed = documentLinkSyncSchema.safeParse(payload);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });

  const sourceId = parsedId.data;
  const sourceExists = await ensureDocumentExistsForWorkspace(sourceId, workspaceId);
  if (!sourceExists) return res.status(404).json({ error: 'Document not found' });

  const extractedIds = buildSyncedLinkSet(parsed.data);
  const uniqueExtractedIds = Array.from(new Set(extractedIds));

  if (uniqueExtractedIds.length === 0) {
    await pool.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
    return res.status(200).json({ success: true, document_id: sourceId, linked_document_ids: [] } satisfies LinkSyncResponse);
  }

  const targetsResult = await pool.query(
    `SELECT id FROM documents
     WHERE id = ANY($1::uuid[])
       AND workspace_id = $2
       AND deleted_at IS NULL`,
    [uniqueExtractedIds, workspaceId]
  );

  if (targetsResult.rows.length !== uniqueExtractedIds.filter((id) => id !== sourceId).length) {
    return res.status(400).json({ error: 'One or more target documents not found' });
  }

  const allowedTargetIds = new Set(targetsResult.rows.map((row) => row.id));
  const filteredTargetIds = uniqueExtractedIds.filter((id) => allowedTargetIds.has(id) && id !== sourceId);

  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);

    if (filteredTargetIds.length > 0) {
      const values = filteredTargetIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
      const params = filteredTargetIds.flatMap((targetId) => [sourceId, targetId]);
      await client.query(
        `INSERT INTO document_links (source_id, target_id)
         VALUES ${values}
         ON CONFLICT (source_id, target_id) DO UPDATE SET updated_at = NOW()`,
        params
      );
    }

    const responseRows = await client.query(
      `SELECT DISTINCT target_id
       FROM document_links
       WHERE source_id = $1
       ORDER BY target_id ASC`,
      [sourceId]
    );

    await client.query('COMMIT');
    return res.status(200).json({
      success: true,
      document_id: sourceId,
      linked_document_ids: responseRows.rows.map((row) => row.target_id),
    } satisfies LinkSyncResponse);
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
});

export default router;

