import {
  useMutation,
  useQuery,
  useQueryClient,
  type UseMutationResult,
  type UseQueryResult,
} from '@tanstack/react-query';

export type CommentId = string;

export interface CommentAuthor {
  id?: string;
  name?: string;
  email?: string;
  avatarUrl?: string | null;
}

export interface Comment {
  id: CommentId;
  documentId: string;
  parentId?: CommentId | null;
  body: string;
  resolved: boolean;
  createdAt?: string;
  updatedAt?: string;
  author?: CommentAuthor | null;
  replies?: Comment[];
}

export interface CommentsQueryParams {
  documentId: string;
}

export interface CreateCommentInput {
  documentId: string;
  body: string;
}

export interface ReplyCommentInput {
  documentId: string;
  parentId: CommentId;
  body: string;
}

export interface UpdateCommentInput {
  documentId: string;
  commentId: CommentId;
  body: string;
}

export interface ResolveCommentInput {
  documentId: string;
  commentId: CommentId;
  resolved: boolean;
}

export interface DeleteCommentInput {
  documentId: string;
  commentId: CommentId;
}

const commentsQueryKeys = {
  all: ['comments'] as const,
  list: (documentId: string) => [...commentsQueryKeys.all, documentId] as const,
};

async function requestJson<T>(input: RequestInfo | URL, init?: RequestInit): Promise<T> {
  const response = await fetch(input, {
    headers: {
      'Content-Type': 'application/json',
      ...(init?.headers ?? {}),
    },
    ...init,
  });

  if (!response.ok) {
    const message = await response.text().catch(() => '');
    throw new Error(message || `Request failed with status ${response.status}`);
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return (await response.json()) as T;
}

async function fetchComments(documentId: string): Promise<Comment[]> {
  return requestJson<Comment[]>(`/api/documents/${documentId}/comments`);
}

async function createComment(input: CreateCommentInput): Promise<Comment> {
  return requestJson<Comment>(`/api/documents/${input.documentId}/comments`, {
    method: 'POST',
    body: JSON.stringify({ body: input.body }),
  });
}

async function replyComment(input: ReplyCommentInput): Promise<Comment> {
  return requestJson<Comment>(`/api/documents/${input.documentId}/comments/${input.parentId}/replies`, {
    method: 'POST',
    body: JSON.stringify({ body: input.body }),
  });
}

async function updateComment(input: UpdateCommentInput): Promise<Comment> {
  return requestJson<Comment>(`/api/documents/${input.documentId}/comments/${input.commentId}`, {
    method: 'PATCH',
    body: JSON.stringify({ body: input.body }),
  });
}

async function resolveComment(input: ResolveCommentInput): Promise<Comment> {
  return requestJson<Comment>(`/api/documents/${input.documentId}/comments/${input.commentId}/resolve`, {
    method: 'POST',
    body: JSON.stringify({ resolved: input.resolved }),
  });
}

async function deleteComment(input: DeleteCommentInput): Promise<void> {
  await requestJson<void>(`/api/documents/${input.documentId}/comments/${input.commentId}`, {
    method: 'DELETE',
  });
}

export function useCommentsQuery(
  params: CommentsQueryParams,
): UseQueryResult<Comment[], Error> {
  return useQuery({
    queryKey: commentsQueryKeys.list(params.documentId),
    queryFn: () => fetchComments(params.documentId),
    enabled: Boolean(params.documentId),
  });
}

export function useCreateCommentMutation(): UseMutationResult<Comment, Error, CreateCommentInput> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: createComment,
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: commentsQueryKeys.list(variables.documentId) });
    },
  });
}

export function useReplyCommentMutation(): UseMutationResult<Comment, Error, ReplyCommentInput> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: replyComment,
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: commentsQueryKeys.list(variables.documentId) });
    },
  });
}

export function useUpdateCommentMutation(): UseMutationResult<Comment, Error, UpdateCommentInput> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: updateComment,
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: commentsQueryKeys.list(variables.documentId) });
    },
  });
}

export function useResolveCommentMutation(): UseMutationResult<Comment, Error, ResolveCommentInput> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: resolveComment,
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: commentsQueryKeys.list(variables.documentId) });
    },
  });
}

export function useDeleteCommentMutation(): UseMutationResult<void, Error, DeleteCommentInput> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: deleteComment,
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: commentsQueryKeys.list(variables.documentId) });
    },
  });
}

