    14	}
    15	
    16	export function DocumentEditor({ documentId, content, onContentChange }: DocumentEditorProps) {
    17	  const { data: comments = [] } = useCommentsQuery(documentId);
    18	  const createComment = useCreateComment();
    19	  const resolveComment = useResolveComment();
    20	  const [pendingSelection, setPendingSelection] = useState<{ from: number; to: number } | null>(null);
    21	
    22	  const editor = useEditor({
    23	    extensions: [
    24	      StarterKit,
    25	      CommentMark.configure({
    26	        onAddComment: (commentId) => {
    27	          void resolveComment.mutateAsync({ id: commentId }).catch(() => undefined);
    28	        },
    29	      }),
    30	      ImageUploadExtension,
    31	      CommentDisplayExtension,
    32	    ],
    33	    content,
    34	    onUpdate: ({ editor }) => {
    35	      onContentChange?.(editor.getJSON());
    36	    },
    37	    onSelectionUpdate: ({ editor }) => {
    38	      if (editor.state.selection.empty) return;
    39	      const { from, to } = editor.state.selection;
    40	      setPendingSelection({ from, to });
    41	    },
    42	  });
    43	
    44	  const handleCreateComment = useCallback(async () => {
    45	    if (!editor || !pendingSelection) return;
    46	    const commentId = crypto.randomUUID();
    47	    editor.chain().focus().setTextSelection(pendingSelection).setComment(commentId).run();
    48	    await createComment.mutateAsync({ documentId, content: 'New comment thread', comment_id: commentId });
    49	  }, [createComment, documentId, editor, pendingSelection]);
    50	
    51	  const handleUploadImage = useCallback(() => {
    52	    if (!editor) return;
    53	    triggerImageUpload(editor);
    54	  }, [editor]);
    55	
    56	  const commentsCount = useMemo(() => comments.reduce((count: number, thread: CommentThread) => count + (thread.replies.length || 0) + (thread.root ? 1 : 0), 0), [comments]);
    57	
    58	  return (
    59	    <div className="flex h-full flex-col gap-2">
    60	      <div className="flex items-center gap-2 border-b border-border pb-2">
    61	        <button type="button" className="rounded bg-primary px-3 py-1 text-sm text-primary-foreground" onClick={handleUploadImage}>
    62	          Upload image
    63	        </button>
    64	        <button type="button" className="rounded border px-3 py-1 text-sm" onClick={handleCreateComment} disabled={!pendingSelection}>
    65	          Add comment
    66	        </button>
    67	        <span className="text-xs text-muted">{commentsCount} comment entries</span>
    68	      </div>
    69	      <EditorContent editor={editor} />
    70	    </div>
    71	  );
    72	}
