     5	import { Extension } from '@tiptap/core';
     6	import { Plugin, PluginKey } from '@tiptap/pm/state';
     7	import { Node as ProseMirrorNode } from '@tiptap/pm/model';
     8	import { Editor } from '@tiptap/react';
     9	import { uploadFile, isImageFile, type UploadProgress } from '@/services/upload.js';
    10	import { registerUpload, updateUploadProgress, unregisterUpload } from '@/services/uploadTracker.js';
    11	
    12	function getUploadedImageUrl(result: Awaited<ReturnType<typeof uploadFile>>): string {
    13	  return result.url || result.cdnUrl || result.assetUrl || `/api/files/${result.fileId}`;
    14	}
    15	
    16	function isImageUploadSupportedUrl(url: string): boolean {
    17	  return typeof url === 'string' && url.length > 0;
    18	}
    19	
    20	export interface ImageUploadOptions {
    21	  /**
    22	   * Callback when an image upload starts
    23	   */
    24	  onUploadStart?: (file: File) => void;
    25	  /**
    26	   * Callback when an image upload completes
    27	   */
    28	  onUploadComplete?: (cdnUrl: string) => void;
    29	  /**
    30	   * Callback when an image upload fails
    31	   */
    32	  onUploadError?: (error: Error) => void;
    33	  /**
    34	   * AbortController for cancelling uploads on navigation/cleanup
    35	   * When aborted, pending uploads will be cancelled and won't update the document
    36	   */
    37	  abortController?: AbortController;
    38	}
    39	
    40	export const ImageUploadExtension = Extension.create<ImageUploadOptions>({
    41	  name: 'imageUpload',
    42	
    43	  addOptions() {
    44	    return {
    45	      onUploadStart: undefined,
    46	      onUploadComplete: undefined,
    47	      onUploadError: undefined,
    48	      abortController: undefined,
    49	    };
    50	  },
    51	
    52	  addProseMirrorPlugins() {
    53	    const editor = this.editor as Editor;
    54	    const options = this.options;
    55	
    56	    return [
    57	      new Plugin({
    58	        key: new PluginKey('imageUpload'),
    59	        props: {
    60	          handlePaste(view, event) {
    61	            const items = Array.from(event.clipboardData?.items || []);
    62	            const imageItem = items.find(
    63	              (item) => item.type.startsWith('image/')
    64	            );
    65	
    66	            if (!imageItem) {
    67	              return false;
    68	            }
    69	
    70	            event.preventDefault();
    71	
    72	            const file = imageItem.getAsFile();
    73	            if (!file) return false;
    74	
    75	            handleImageUpload(editor, file, options);
    76	            return true;
    77	          },
    78	
    79	          handleDrop(view, event) {
    80	            const files = Array.from(event.dataTransfer?.files || []);
    81	            const imageFiles = files.filter((file) => isImageFile(file.type));
    82	
    83	            if (imageFiles.length === 0) {
    84	              return false;
    85	            }
    86	
    87	            event.preventDefault();
    88	
    89	            // Upload all dropped images
    90	            imageFiles.forEach((file) => {
    91	              handleImageUpload(editor, file, options);
    92	            });
    93	
    94	            return true;
    95	          },
    96	        },
    97	      }),
    98	    ];
    99	  },
   100	});
   101	
   102	/**
   103	 * Handle image upload and insertion into editor
   104	 */
   105	async function handleImageUpload(
   106	  editor: Editor,
   107	  file: File,
   108	  options: ImageUploadOptions
   109	) {
   110	  const signal = options.abortController?.signal;
   111	
   112	  // Check if already aborted (e.g., user navigated away before upload started)
   113	  if (signal?.aborted) {
   114	    return;
   115	  }
   116	
   117	  options.onUploadStart?.(file);
   118	
   119	  // Generate unique upload ID for tracking navigation warnings
   120	  const uploadId = crypto.randomUUID();
   121	  registerUpload(uploadId, file.name);
   122	
   123	  // Insert image with local preview for immediate feedback
   124	  const previewUrl = URL.createObjectURL(file);
   125	  insertImage(editor, previewUrl, file.name);
   126	
   127	  // Revoke the preview URL once the image is replaced or upload stops
   128	  const cleanupPreview = () => URL.revokeObjectURL(previewUrl);
   129	
   130	  try {
   131	    const result = await uploadFile(
   132	      file,
   133	      (progress: UploadProgress) => {
   134	        // Update global tracker for navigation warning
   135	        updateUploadProgress(uploadId, progress.progress);
   136	      },
   137	      signal
   138	    );
   139	
   140	    // Check if aborted before updating the editor
   141	    // This prevents updating a stale editor after navigation
   142	    if (signal?.aborted) {
   143	      console.log('Image upload completed but was cancelled - not updating editor');
   144	      return;
   145	    }
   146	
   147	    const uploadedUrl = getUploadedImageUrl(result);
   148	    if (!isImageUploadSupportedUrl(uploadedUrl)) {
   149	      throw new Error('Upload did not return a usable image URL');
   150	    }
   151	
   152	    const { state, view } = editor;
   153	    const { doc } = state;
   154	
   155	    let imagePos: number | null = null;
   156	
   157	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   158	      if (node.type.name === 'image' && node.attrs.src === previewUrl) {
   159	        imagePos = pos;
   160	        return false;
   161	      }
   162	      return true;
   163	    });
   164	
   165	    if (imagePos !== null) {
   166	      const transaction = state.tr.setNodeMarkup(imagePos, undefined, {
   167	        ...doc.nodeAt(imagePos)?.attrs,
   168	        src: uploadedUrl,
   169	      });
   170	      view.dispatch(transaction);
   171	    }
   172	
   173	    // If the preview node is no longer present, insert the persisted image URL
   174	    if (imagePos === null && !signal?.aborted) {
   175	      insertImage(editor, uploadedUrl, file.name);
   176	    }
   177	
   178	    cleanupPreview();
   179	    // Upload complete - unregister from tracker
   180	    unregisterUpload(uploadId);
   181	    options.onUploadComplete?.(uploadedUrl);
   182	  } catch (error) {
   183	    // Upload failed - unregister from tracker
   184	    unregisterUpload(uploadId);
   185	    cleanupPreview();
   186	    // Don't report cancellation as an error - it's intentional
   187	    if (error instanceof DOMException && error.name === 'AbortError') {
   188	      console.log('Image upload cancelled');
   189	      return;
   190	    }
   191	
   192	    console.error('Image upload failed:', error);
   193	    options.onUploadError?.(
   194	      error instanceof Error ? error : new Error('Upload failed')
   195	    );
   196	
   197	    // Optionally remove the failed image or show error state
   198	    // For now, leave the preview as fallback
   199	  }
   200	}
   201	
   202	/**
   203	 * Convert a File to a data URL
   204	 */
   205	function fileToDataUrl(file: File): Promise<string> {
   206	  return new Promise((resolve, reject) => {
   207	    const reader = new FileReader();
   208	    reader.onload = () => resolve(reader.result as string);
   209	    reader.onerror = reject;
   210	    reader.readAsDataURL(file);
   211	  });
   212	}
   213	
   214	/**
   215	 * Trigger file picker for image upload
   216	 */
   217	function insertImage(editor: Editor, src: string, fileName: string) {
   218	  editor
   219	    .chain()
   220	    .focus()
   221	    .setImage({
   222	      src,
   223	      alt: fileName,
   224	      title: fileName,
   225	    })
   226	    .run();
   227	}
   228	
   229	export function triggerImageUpload(
   230	  editor: Editor,
   231	  options: ImageUploadOptions = {}
   232	) {
   233	  // Check if already aborted
   234	  if (options.abortController?.signal?.aborted) {
   235	    return;
   236	  }
   237	
   238	  const input = document.createElement('input');
   239	  input.type = 'file';
   240	  input.accept = 'image/*';
   241	  input.multiple = true;
   242	
   243	  input.onchange = () => {
   244	    // Check again in case it was aborted while file picker was open
   245	    if (options.abortController?.signal?.aborted) {
   246	      return;
   247	    }
   248	    const files = Array.from(input.files || []);
   249	    files.forEach((file) => {
   250	      handleImageUpload(editor, file, options);
   251	    });
   252	    input.remove();
   253	  };
   254	
   255	  input.click();
   256	}
