{"success":true,"content":"     1	import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
     2	
     3	import { apiDelete, apiGet, apiPatch, apiPost } from '@/lib/api';
     4	
     5	export type CommentStatus = 'open' | 'resolved' | 'deleted';
     6	
     7	export interface CommentUser {
     8	  id: string;
     9	  name?: string | null;
    10	  email?: string | null;
    11	  avatarUrl?: string | null;
    12	}
    13	
    14	export interface CommentThread {
    15	  id: string;
    16	  postId: string;
    17	  parentId: string | null;
    18	  content: string;
    19	  status: CommentStatus;
    20	  createdAt: string;
    21	  updatedAt: string;
    22	  resolvedAt?: string | null;
    23	  resolvedById?: string | null;
    24	  author?: CommentUser | null;
    25	  replies?: CommentThread[];
    26	}
    27	
    28	export interface CommentsThreadListResponse {
    29	  threads: CommentThread[];
    30	}
    31	
    32	export interface CreateCommentInput {
    33	  postId: string;
    34	  content: string;
    35	  parentId?: string | null;
    36	}
    37	
    38	export interface UpdateCommentInput {
    39	  content: string;
    40	}
    41	
    42	export interface ResolveCommentInput {
    43	  resolved: boolean;
    44	}
    45	
    46	const COMMENTS_QUERY_KEY = ['comments'] as const;
    47	
    48	const commentsKey = (postId: string) => [...COMMENTS_QUERY_KEY, postId] as const;
    49	
    50	async function fetchCommentThreads(postId: string): Promise<CommentThread[]> {
    51	  const response = await apiGet(`/api/posts/${postId}/comments`);
    52	  if (!response.ok) {
    53	    const error = new Error('Failed to fetch comments') as Error & { status: number };
    54	    error.status = response.status;
    55	    throw error;
    56	  }
    57	  const data = (await response.json()) as CommentsThreadListResponse;
    58	  return data.threads;
    59	}
    60	
    61	async function createComment(input: CreateCommentInput): Promise<CommentThread> {
    62	  const response = await apiPost(`/api/posts/${input.postId}/comments`, {
    63	    content: input.content,
    64	    parentId: input.parentId ?? null,
    65	  });
    66	  if (!response.ok) {
    67	    const error = new Error('Failed to create comment') as Error & { status: number };
    68	    error.status = response.status;
    69	    throw error;
    70	  }
    71	  return response.json();
    72	}
    73	
    74	async function replyToComment(commentId: string, content: string): Promise<CommentThread> {
    75	  const response = await apiPost(`/api/comments/${commentId}/replies`, { content });
    76	  if (!response.ok) {
    77	    const error = new Error('Failed to create reply') as Error & { status: number };
    78	    error.status = response.status;
    79	    throw error;
    80	  }
    81	  return response.json();
    82	}
    83	
    84	async function updateComment(commentId: string, content: string): Promise<CommentThread> {
    85	  const response = await apiPatch(`/api/comments/${commentId}`, { content });
    86	  if (!response.ok) {
    87	    const error = new Error('Failed to update comment') as Error & { status: number };
    88	    error.status = response.status;
    89	    throw error;
    90	  }
    91	  return response.json();
    92	}
    93	
    94	async function resolveComment(commentId: string, resolved: boolean): Promise<CommentThread> {
    95	  const response = await apiPatch(`/api/comments/${commentId}/resolve`, { resolved });
    96	  if (!response.ok) {
    97	    const error = new Error('Failed to resolve comment') as Error & { status: number };
    98	    error.status = response.status;
    99	    throw error;
   100	  }
   101	  return response.json();
   102	}
   103	
   104	async function deleteComment(commentId: string): Promise<void> {
   105	  const response = await apiDelete(`/api/comments/${commentId}`);
   106	  if (!response.ok) {
   107	    const error = new Error('Failed to delete comment') as Error & { status: number };
   108	    error.status = response.status;
   109	    throw error;
   110	  }
   111	}
   112	
   113	function upsertThread(threads: CommentThread[], thread: CommentThread): CommentThread[] {
   114	  const idx = threads.findIndex((t) => t.id === thread.id);
   115	  if (idx === -1) return [thread, ...threads];
   116	  return threads.map((t) => (t.id === thread.id ? thread : t));
   117	}
   118	
   119	function removeThread(threads: CommentThread[], commentId: string): CommentThread[] {
   120	  return threads.filter((t) => t.id !== commentId);
   121	}
   122	
   123	export function useCommentsQuery(postId?: string) {
   124	  const queryClient = useQueryClient();
   125	  const key = postId ? commentsKey(postId) : commentsKey('__disabled__');
   126	
   127	  const commentsQuery = useQuery({
   128	    queryKey: key,
   129	    queryFn: () => {
   130	      if (!postId) throw new Error('postId is required');
   131	      return fetchCommentThreads(postId);
   132	    },
   133	    enabled: Boolean(postId),
   134	  });
   135	
   136	  const createMutation = useMutation({
   137	    mutationFn: createComment,
   138	    onSuccess: async (created, variables) => {
   139	      await queryClient.cancelQueries({ queryKey: commentsKey(variables.postId) });
   140	      queryClient.setQueryData<CommentThread[]>(commentsKey(variables.postId), (old = []) => upsertThread(old, created));
   141	      await queryClient.invalidateQueries({ queryKey: commentsKey(variables.postId) });
   142	    },
   143	  });
   144	
   145	  const replyMutation = useMutation({
   146	    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => replyToComment(commentId, content),
   147	    onSuccess: async (reply) => {
   148	      if (!postId) return;
   149	      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
   150	      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, reply));
   151	      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
   152	    },
   153	  });
   154	
   155	  const updateMutation = useMutation({
   156	    mutationFn: ({ commentId, content }: { commentId: string; content: string }) => updateComment(commentId, content),
   157	    onSuccess: async (updated) => {
   158	      if (!postId) return;
   159	      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
   160	      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, updated));
   161	      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
   162	    },
   163	  });
   164	
   165	  const resolveMutation = useMutation({
   166	    mutationFn: ({ commentId, resolved }: { commentId: string; resolved: boolean }) => resolveComment(commentId, resolved),
   167	    onSuccess: async (updated) => {
   168	      if (!postId) return;
   169	      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
   170	      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => upsertThread(old, updated));
   171	      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
   172	    },
   173	  });
   174	
   175	  const deleteMutation = useMutation({
   176	    mutationFn: deleteComment,
   177	    onSuccess: async (_void, commentId) => {
   178	      if (!postId) return;
   179	      await queryClient.cancelQueries({ queryKey: commentsKey(postId) });
   180	      queryClient.setQueryData<CommentThread[]>(commentsKey(postId), (old = []) => removeThread(old, commentId));
   181	      await queryClient.invalidateQueries({ queryKey: commentsKey(postId) });
   182	    },
   183	  });
   184	
   185	  return {
   186	    ...commentsQuery,
   187	    comments: commentsQuery.data ?? [],
   188	    createComment: createMutation.mutateAsync,
   189	    replyToComment: replyMutation.mutateAsync,
   190	    updateComment: updateMutation.mutateAsync,
   191	    resolveComment: resolveMutation.mutateAsync,
   192	    deleteComment: deleteMutation.mutateAsync,
   193	    isCreatingComment: createMutation.isPending,
   194	    isReplyingToComment: replyMutation.isPending,
   195	    isUpdatingComment: updateMutation.isPending,
   196	    isResolvingComment: resolveMutation.isPending,
   197	    isDeletingComment: deleteMutation.isPending,
   198	  };
   199	}
