    11	}
    12	
    13	function findCommentPositions(doc: ProseMirrorNode): Map<string, number> {
    14	  const positions = new Map<string, number>();
    15	
    16	  doc.descendants((node: ProseMirrorNode, pos: number) => {
    17	    if (node.isText) {
    18	      for (const mark of node.marks) {
    19	        if (mark.type.name === 'commentMark' && mark.attrs.commentId) {
    20	          const commentId = mark.attrs.commentId;
    21	          const $pos = doc.resolve(pos);
    22	          const blockEnd = $pos.end(Math.max(1, $pos.depth));
    23	          positions.set(commentId, blockEnd);
    24	        }
    25	      }
    26	    }
    27	  });
    28	
    29	  return positions;
    30	}
    31	
    32	export const commentDisplayPluginKey = new PluginKey('commentDisplay');
    33	
    34	interface CommentDisplayStorage {
    35	  comments: CommentThread[];
    36	  onReply: ((commentId: string, content: string) => void) | null;
    37	  onResolve: ((commentId: string, resolved: boolean) => void) | null;
    38	  pendingCommentId: string | null;
    39	  pendingCommentText: string;
    40	  onSubmitComment: ((commentId: string, content: string) => void) | null;
    41	  onCancelComment: ((commentId: string) => void) | null;
    42	}
    43	
    44	function InlineCommentThread({ thread, quotedText }: { thread: CommentThread; quotedText: string }) {
    45	  const root = getThreadRoot(thread);
    46	  const replies = thread.replies;
    47	  const isResolved = getCommentThreadResolvedAt(thread) !== null;
    48	
    49	  if (!root) {
    50	    return document.createElement('div');
    51	  }
    52	
    53	  const container = document.createElement('div');
    54	  container.className = 'comment-thread-inline';
    55	  container.setAttribute('data-comment-thread', root.comment_id);
    56	  container.contentEditable = 'false';
    57	
    58	  if (isResolved) {
    59	    container.innerHTML = `
    60	      <div class="comment-thread-resolved" data-comment-id="${escapeHtml(root.comment_id)}">
    61	        <span class="comment-resolved-icon">✓</span>
    62	        <span class="comment-resolved-text">Resolved by ${escapeHtml(root.author_id)} · ${formatRelativeTime(getCommentThreadResolvedAt(thread) ?? root.updated_at)}</span>
    63	        <span class="comment-resolved-toggle">Show thread</span>
    64	      </div>
    65	    `;
    66	  } else {
    67	    const quotedHtml = quotedText ? `<div class="comment-quoted-text">"${escapeHtml(quotedText)}"</div>` : '';
    68	
    69	    let repliesHtml = '';
    70	    for (const reply of replies) {
    71	      repliesHtml += `
    72	        <div class="comment-reply">
    73	          <div class="comment-header">
    74	            <span class="comment-author">${escapeHtml(reply.author_id)}</span>
    75	            <span class="comment-time">${formatRelativeTime(reply.created_at)}</span>
    76	          </div>
    77	          <div class="comment-body">${escapeHtml(reply.content)}</div>
    78	        </div>
    79	      `;
    80	    }
    81	
    82	    container.innerHTML = `
    83	      ${quotedHtml}
    84	      <div class="comment-root">
    85	        <div class="comment-header">
    86	          <span class="comment-author">${escapeHtml(root.author_id)}</span>
    87	          <span class="comment-time">${formatRelativeTime(root.created_at)}</span>
