  const commentId = crypto.randomUUID();
  editor.chain().focus().setTextSelection(pendingSelection).setComment(commentId).run();
  await createComment.mutateAsync({ documentId, content: 'New comment thread', comment_id: commentId });
}, [createComment, documentId, editor, pendingSelection]);

const handleUploadImage = useCallback(() => {
  if (!editor) return;
  triggerImageUpload(editor);
}, [editor]);

