tool_input.new_string:
const { comments = [], createComment, replyToComment, resolveComment } = useCommentsQuery(documentId);
const [pendingSelection, setPendingSelection] = useState<{ from: number; to: number } | null>(null);
const [pendingCommentId, setPendingCommentId] = useState<string | null>(null);
const editorRef = useRef<ReturnType<typeof useEditor> | null>(null);

const handleUploadImage = useCallback(() => {
  if (!editorRef.current) return;
  triggerImageUpload(editorRef.current);
}, []);

const handleCreateComment = useCallback(async () => {
  if (!editorRef.current || !pendingSelection) return;
  const commentId = crypto.randomUUID();
  editorRef.current.chain().focus().setTextSelection(pendingSelection).setComment(commentId).run();
  setPendingCommentId(commentId);
  await createComment({ postId: documentId, content: 'New comment thread' });
}, [createComment, documentId, pendingSelection]);

const handleReply = useCallback(async (commentId: string, content: string) => {
  await replyToComment({ commentId, content });
}, [replyToComment]);

const handleResolve = useCallback(async (commentId: string, resolved: boolean) => {
  await resolveComment({ commentId, resolved });
}, [resolveComment]);

const editor = useEditor({
  extensions: [
    StarterKit,
    CommentMark.configure({
      onAddComment: (commentId) => {
        void resolveComment({ commentId, resolved: true }).catch(() => undefined);
      },
    }),
    ImageUploadExtension,
    CommentDisplayExtension.configure({
      onReply: handleReply,
      onResolve: handleResolve,
    }),
  ],
  content,
  onUpdate: ({ editor }) => {
    onContentChange?.(editor.getJSON());
  },
  onSelectionUpdate: ({ editor }) => {
    if (editor.state.selection.empty) return;
    const { from, to } = editor.state.selection;
    setPendingSelection({ from, to });
  },
});

useEffect(() => {
  editorRef.current = editor;
}, [editor]);

const commentsCount = useMemo(() => comments.reduce((count: number, thread: CommentThread) => count + (thread.replies?.length || 0) + 1, 0), [comments]);

